{
  "name": "Blender Node Visualizer",
  "description": "A read-only visualization tool for AI-generated Blender shader node graphs."
}

export type DataType = 'float' | 'vector3' | 'color' | 'string' | string;

export interface Position {
  x: number;
  y: number;
}

export interface Size {
  width: number;
  height: number;
}

export interface NodePort {
  id: string;
  name: string;
  type: DataType;
  connected?: boolean;
}

export interface NodeProperty {
  name: string;
  type: DataType;
  value: any;
}

export interface NodeData {
  id: string;
  name: string;
  type: string;
  position: Position;
  size: Size;
  properties?: NodeProperty[];
  inputs?: NodePort[];
  outputs?: NodePort[];
}

export interface ConnectionData {
  from: string;
  to: string;
}

export interface GraphSchema {
  nodes: NodeData[];
  connections: ConnectionData[];
}

export interface ViewportState {
  x: number;
  y: number;
  scale: number;
}

import { DataType } from './types';

// Blender Shader Editor Colors
export const TYPE_COLORS: Record<string, string> = {
  float: '#A1A1A1', // Grey
  vector3: '#6363C7', // Purple
  color: '#C7C729', // Yellow
  string: '#63C7C7', // Cyan/Blueish
  shader: '#63C763', // Green (Common in Blender)
  unknown: '#FF4444', // Red for errors
};

export const UI_SIZES = {
  HEADER_HEIGHT: 32,
  PORT_HEIGHT: 24,
  PROPERTY_HEIGHT: 28, // Slightly taller for values
  PORT_RADIUS: 5,
  NODE_PADDING_X: 12,
  NODE_PADDING_Y: 8,
};

