import { TYPE_COLORS, UI_SIZES } from './constants';
import { DataType, GraphSchema, NodeData } from './types';

// --- Color Helpers ---

export const getPortColor = (type: DataType): string => {
  return TYPE_COLORS[type.toLowerCase()] || TYPE_COLORS.float; // Default to grey/float if unknown
};

export const isValidVector3 = (val: any): boolean => {
  return Array.isArray(val) && val.length === 3 && val.every(n => typeof n === 'number');
};

export const isValidColor = (val: any): boolean => {
  // Blender usually sends [R, G, B] or [R, G, B, A]
  return Array.isArray(val) && (val.length === 3 || val.length === 4) && val.every(n => typeof n === 'number');
};

export const formatVector = (val: number[]): string => {
  return `[${val.map(n => n.toFixed(2)).join(', ')}]`;
};

// --- Geometry Helpers ---

/**
 * Calculates the absolute position of a port within the global canvas space.
 * Used for drawing connection lines.
 */
export const getPortPosition = (
  node: NodeData,
  portId: string,
  type: 'input' | 'output'
): { x: number; y: number } | null => {

  const ports = type === 'input' ? node.inputs : node.outputs;
  if (!ports) return null;

  const index = ports.findIndex(p => p.id === portId);
  if (index === -1) return null;

  // Vertical calculation
  // Header + Properties + Previous Ports
  let currentY = UI_SIZES.HEADER_HEIGHT + UI_SIZES.NODE_PADDING_Y;

  if (node.properties) {
    currentY += node.properties.length * UI_SIZES.PROPERTY_HEIGHT;
  }

  // If it's an output, it aligns with inputs visually in list, 
  // but logically inputs usually come first in height if we were auto-layouting.
  // However, in Blender nodes, Inputs and Outputs are often lists on Left and Right.
  // We assume a simple stack: Properties -> Inputs -> Outputs (if they share vertical space?)
  // Actually, usually Inputs are on left, Outputs on right. They start at same Y after properties.
  // But to be robust, let's just stack them based on index relative to top of "Content Area"

  // Correction: In Blender, Inputs and Outputs are separate columns. 
  // We will assume they start at the same Y offset after properties.

  const portYOffset = index * UI_SIZES.PORT_HEIGHT + (UI_SIZES.PORT_HEIGHT / 2);

  const y = node.position.y + currentY + portYOffset;

  const x = type === 'input' 
    ? node.position.x 
    : node.position.x + node.size.width;

  return { x, y };
};

// --- Connection Path ---

export const calculateBezierPath = (
  x1: number,
  y1: number,
  x2: number,
  y2: number
): string => {
  const dist = Math.abs(x2 - x1) * 0.5; // Curvature strength
  // Ensure the line goes out to the right and comes in from the left
  const cp1x = x1 + Math.max(dist, 50); 
  const cp1y = y1;
  const cp2x = x2 - Math.max(dist, 50);
  const cp2y = y2;

  return `M ${x1} ${y1} C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${x2} ${y2}`;
};

// --- Parsing ---

export const parseGraphJSON = (json: string): { schema: GraphSchema | null; error: string | null } => {
  try {
    const parsed = JSON.parse(json);
    if (!parsed.nodes || !Array.isArray(parsed.nodes)) {
      return { schema: null, error: "Invalid JSON: 'nodes' array missing." };
    }
    // Basic sanitization
    parsed.connections = parsed.connections || [];
    return { schema: parsed as GraphSchema, error: null };
  } catch (e: any) {
    return { schema: null, error: e.message || "Invalid JSON syntax." };
  }
};

import React from 'react';
import { calculateBezierPath, getPortColor } from '../../utils';
import { DataType } from '../../types';

interface ConnectionLineProps {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
  type: DataType;
}

export const ConnectionLine: React.FC<ConnectionLineProps> = ({ x1, y1, x2, y2, type }) => {
  const pathData = calculateBezierPath(x1, y1, x2, y2);
  const color = getPortColor(type);

  return (
    <g>
      {/* Shadow/Outline for better visibility on dark bg */}
      <path
        d={pathData}
        fill="none"
        stroke="#171717" // Neutral-900 matches bg
        strokeWidth="4"
        strokeLinecap="round"
        className="opacity-50"
      />
      {/* Actual Line */}
      <path
        d={pathData}
        fill="none"
        stroke={color}
        strokeWidth="2"
        strokeLinecap="round"
        className="transition-colors duration-200"
      />
    </g>
  );
};

import React from 'react';
import { NodeData, NodePort, NodeProperty } from '../../types';
import { UI_SIZES, TYPE_COLORS } from '../../constants';
import { getPortColor, isValidVector3, isValidColor, formatVector } from '../../utils';
import { AlertTriangle, HelpCircle } from 'lucide-react';

interface NodeWidgetProps {
  data: NodeData;
}

const PortDot: React.FC<{ type: string; isConnected?: boolean }> = ({ type, isConnected }) => {
  const color = getPortColor(type);
  return (
    <div 
      className={`w-3 h-3 rounded-full border border-neutral-900 ${isConnected ? '' : 'opacity-80'}`}
      style={{ backgroundColor: color }}
    />
  );
};

const ValueDisplay: React.FC<{ property: NodeProperty }> = ({ property }) => {
  const { type, value } = property;

  if (type === 'float') {
    const num = typeof value === 'number' ? value : parseFloat(value);
    if (isNaN(num)) return <span className="text-red-500 text-xs">NaN</span>;
    return (
      <div className="bg-neutral-700 px-2 py-0.5 rounded text-neutral-300 text-xs font-mono min-w-[40px] text-center">
        {num.toFixed(3)}
      </div>
    );
  }

  if (type === 'vector3') {
    if (!isValidVector3(value)) {
       return <span className="text-red-500 text-[10px] flex items-center gap-1"><AlertTriangle size={10} /> Invalid Data</span>;
    }
    return (
      <div className="flex gap-1 text-[10px] font-mono">
        <span className="bg-red-900/50 px-1 rounded text-red-200">{value[0].toFixed(1)}</span>
        <span className="bg-green-900/50 px-1 rounded text-green-200">{value[1].toFixed(1)}</span>
        <span className="bg-blue-900/50 px-1 rounded text-blue-200">{value[2].toFixed(1)}</span>
      </div>
    );
  }

  if (type === 'color') {
    if (!isValidColor(value)) {
       return <div className="w-8 h-4 bg-black rounded border border-red-500 relative flex justify-center items-center"><HelpCircle size={10} className="text-red-500"/></div>;
    }
    const bg = `rgb(${value[0] * 255}, ${value[1] * 255}, ${value[2] * 255})`;
    return (
      <div className="flex items-center gap-2">
         <div className="w-12 h-4 rounded border border-neutral-600 shadow-sm" style={{ backgroundColor: bg }} />
      </div>
    );
  }

  if (type === 'string') {
    return <span className="text-neutral-400 text-xs italic truncate max-w-[100px] block" title={String(value)}>{String(value)}</span>;
  }

  return <span className="text-neutral-500 text-xs">Unknown</span>;
};

export const NodeWidget: React.FC<NodeWidgetProps> = ({ data }) => {
  const { x, y } = data.position;
  const { width, height } = data.size;

  // Determine header color based on specific Blender conventions (simplified)
  let headerClass = "bg-neutral-700";
  if (data.type.includes("Input") || data.type.includes("Coord")) headerClass = "bg-red-900/80"; // Red-ish for Input
  if (data.type.includes("Output")) headerClass = "bg-neutral-800 border-b border-neutral-600";
  if (data.type.includes("Shader")) headerClass = "bg-green-900/60"; // Green-ish for shaders

  return (
    <div
      className="absolute flex flex-col rounded-lg shadow-2xl border border-neutral-700 bg-neutral-800/95 overflow-hidden text-sm select-none"
      style={{
        left: x,
        top: y,
        width: width,
        minHeight: height, // allow growing if content exceeds
      }}
    >
      {/* Header */}
      <div className={`px-3 py-1.5 ${headerClass} text-white font-medium text-xs tracking-wide flex items-center justify-between`}>
        <span className="truncate">{data.name}</span>
      </div>

      {/* Body Content */}
      <div className="flex flex-col flex-1 p-2 gap-1 relative">

        {/* Properties (Internal values) */}
        {data.properties?.map((prop, idx) => (
          <div key={`prop-${idx}`} className="flex items-center justify-between h-7 px-1">
            <span className="text-neutral-300 text-xs">{prop.name}</span>
            <ValueDisplay property={prop} />
          </div>
        ))}

        {/* Inputs & Outputs Area */}
        {/* We stack inputs, then outputs. In standard blender, they share rows but are L/R aligned. 
            Here we just render absolute lists to match the port geometry calculation in Utils. 
            Or we can use flex row to separate left/right columns. */}

        <div className="flex flex-row justify-between mt-1">
            {/* Inputs Column */}
            <div className="flex flex-col gap-1 w-1/2">
                {data.inputs?.map((port) => (
                    <div key={port.id} className="flex items-center gap-2 h-6 -ml-3 pl-1">
                         <PortDot type={port.type} isConnected={port.connected} />
                         <span className="text-neutral-300 text-xs truncate">{port.name}</span>
                    </div>
                ))}
            </div>

             {/* Outputs Column */}
             <div className="flex flex-col gap-1 w-1/2 items-end">
                {data.outputs?.map((port) => (
                    <div key={port.id} className="flex items-center gap-2 h-6 -mr-3 pr-1 justify-end">
                         <span className="text-neutral-300 text-xs truncate text-right">{port.name}</span>
                         <PortDot type={port.type} isConnected={true} /> 
                    </div>
                ))}
            </div>
        </div>

      </div>
    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { GraphSchema, ViewportState } from '../../types';
import { NodeWidget } from './NodeWidget';
import { ConnectionLine } from './ConnectionLine';
import { getPortPosition } from '../../utils';
import { Grid } from 'lucide-react';

interface GraphCanvasProps {
  schema: GraphSchema;
}

export const GraphCanvas: React.FC<GraphCanvasProps> = ({ schema }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [viewport, setViewport] = useState<ViewportState>({ x: 0, y: 0, scale: 1 });
  const [isDragging, setIsDragging] = useState(false);
  const [lastMousePos, setLastMousePos] = useState({ x: 0, y: 0 });

  // Pinch zoom state
  const [initialPinchDist, setInitialPinchDist] = useState<number | null>(null);
  const [initialScale, setInitialScale] = useState<number>(1);

  // --- Pan Logic (Mouse & Touch) ---

  const handlePointerDown = (e: React.PointerEvent) => {
    // Mouse: Right click only (button 2). Touch: Any.
    if (e.pointerType === 'mouse' && e.button !== 2) return;

    // Check if multi-touch (pinch) starts
    if (!e.isPrimary) return; 

    setIsDragging(true);
    setLastMousePos({ x: e.clientX, y: e.clientY });

    // Capture pointer to track outside window
    containerRef.current?.setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging) return;
    if (e.pointerType === 'mouse' && e.button !== 2 && e.buttons !== 2) {
       // Safety: user released right click outside window
       setIsDragging(false);
       return;
    }

    const dx = e.clientX - lastMousePos.x;
    const dy = e.clientY - lastMousePos.y;

    setViewport(prev => ({
      ...prev,
      x: prev.x + dx,
      y: prev.y + dy
    }));

    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    setIsDragging(false);
    setInitialPinchDist(null);
    containerRef.current?.releasePointerCapture(e.pointerId);
  };

  // --- Zoom Logic (Wheel) ---

  const handleWheel = (e: React.WheelEvent) => {
    e.stopPropagation(); // Don't scroll page
    // Calculate new scale
    const zoomFactor = -e.deltaY * 0.001;
    const newScale = Math.min(Math.max(0.1, viewport.scale + zoomFactor), 5);

    // Zoom towards pointer (Simplified: Zoom center for now to avoid complex math in snippet)
    // To implement zoom-to-pointer:
    // 1. Get mouse pos relative to viewport (offset).
    // 2. Adjust viewport x/y based on scale diff.

    // Let's stick to simple zoom for robustness, or try simple pointer tracking:
    // Actually, centered zoom is often less jarring if pointer math is slightly off.

    setViewport(prev => ({
      ...prev,
      scale: newScale
    }));
  };

  // --- Touch Pinch Logic (Native Touch Events) ---

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;

    const onTouchStart = (e: TouchEvent) => {
      if (e.touches.length === 2) {
        const dist = Math.hypot(
          e.touches[0].clientX - e.touches[1].clientX,
          e.touches[0].clientY - e.touches[1].clientY
        );
        setInitialPinchDist(dist);
        setInitialScale(viewport.scale);
      }
    };

    const onTouchMove = (e: TouchEvent) => {
      if (e.touches.length === 2 && initialPinchDist !== null) {
        e.preventDefault(); // Prevent page zoom
        const dist = Math.hypot(
          e.touches[0].clientX - e.touches[1].clientX,
          e.touches[0].clientY - e.touches[1].clientY
        );
        const scaleFactor = dist / initialPinchDist;
        setViewport(prev => ({
          ...prev,
          scale: Math.min(Math.max(0.1, initialScale * scaleFactor), 5)
        }));
      }
    };

    el.addEventListener('touchstart', onTouchStart, { passive: false });
    el.addEventListener('touchmove', onTouchMove, { passive: false });

    return () => {
      el.removeEventListener('touchstart', onTouchStart);
      el.removeEventListener('touchmove', onTouchMove);
    };
  }, [viewport.scale, initialPinchDist, initialScale]);


  // --- Render Connections ---
  // Memoize this or calculate on render? schema is small enough to calc on render usually.
  const connectionLines = schema.connections.map((conn, idx) => {
    const sourceNode = schema.nodes.find(n => n.id === conn.from.split('_')[0]) || schema.nodes.find(n => n.outputs?.some(o => o.id === conn.from));
    const targetNode = schema.nodes.find(n => n.id === conn.to.split('_')[0]) || schema.nodes.find(n => n.inputs?.some(i => i.id === conn.to));

    // Fallback: If ID format is "nodeId_portId" isn't guaranteed, we look for port ID in all nodes.
    // The spec implies port IDs are globally unique.

    const actualSourceNode = schema.nodes.find(n => n.outputs?.some(o => o.id === conn.from));
    const actualTargetNode = schema.nodes.find(n => n.inputs?.some(i => i.id === conn.to));

    if (!actualSourceNode || !actualTargetNode) return null;

    const start = getPortPosition(actualSourceNode, conn.from, 'output');
    const end = getPortPosition(actualTargetNode, conn.to, 'input');

    // Find type for color
    const portDef = actualSourceNode.outputs?.find(o => o.id === conn.from);

    if (start && end && portDef) {
      return (
        <ConnectionLine
          key={`${conn.from}-${conn.to}-${idx}`}
          x1={start.x}
          y1={start.y}
          x2={end.x}
          y2={end.y}
          type={portDef.type}
        />
      );
    }
    return null;
  });

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-[#111] overflow-hidden relative cursor-grab active:cursor-grabbing touch-none"
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onPointerLeave={handlePointerUp}
      onWheel={handleWheel}
      onContextMenu={(e) => e.preventDefault()} // Disable context menu
    >
        {/* Grid Background Pattern */}
        <div 
            className="absolute inset-0 pointer-events-none opacity-20"
            style={{
                backgroundImage: 'linear-gradient(#333 1px, transparent 1px), linear-gradient(90deg, #333 1px, transparent 1px)',
                backgroundSize: `${20 * viewport.scale}px ${20 * viewport.scale}px`,
                backgroundPosition: `${viewport.x}px ${viewport.y}px`
            }}
        />

        {/* Scalable Container */}
        <div 
            style={{
                transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.scale})`,
                transformOrigin: '0 0',
                width: '100%',
                height: '100%',
                position: 'absolute',
                top: 0,
                left: 0
            }}
        >
            {/* Connections Layer (Behind Nodes) */}
            <svg className="absolute top-0 left-0 overflow-visible pointer-events-none w-1 h-1">
                {connectionLines}
            </svg>

            {/* Nodes Layer */}
            {schema.nodes.map(node => (
                <NodeWidget key={node.id} data={node} />
            ))}
        </div>

        {/* HUD / Info */}
        <div className="absolute bottom-4 left-4 bg-black/50 p-2 rounded text-xs text-neutral-400 font-mono pointer-events-none">
            Zoom: {Math.round(viewport.scale * 100)}% | X: {Math.round(viewport.x)} Y: {Math.round(viewport.y)}
        </div>
    </div>
  );
};

import React from 'react';
import { Menu, X, FileJson } from 'lucide-react';

interface ToolbarProps {
  onToggleEditor: () => void;
  showEditor: boolean;
  hasError: boolean;
}

export const Toolbar: React.FC<ToolbarProps> = ({ onToggleEditor, showEditor, hasError }) => {
  return (
    <div className="absolute top-0 left-0 w-full h-14 bg-neutral-900/80 backdrop-blur-md border-b border-neutral-800 flex items-center justify-between px-4 z-50">
      <div className="flex items-center gap-2">
         <div className="w-8 h-8 bg-orange-600 rounded-md flex items-center justify-center text-white font-bold shadow-lg">
           Bn
         </div>
         <h1 className="text-white font-semibold text-lg tracking-tight hidden sm:block">
           Node <span className="text-neutral-400 font-normal">Visualizer</span>
         </h1>
      </div>

      <div className="flex items-center gap-2">
        {hasError && (
          <span className="text-red-500 text-xs font-bold mr-2 animate-pulse">
            Invalid JSON
          </span>
        )}
        <button
          onClick={onToggleEditor}
          className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-colors ${
            showEditor 
              ? 'bg-neutral-800 text-white border border-neutral-700' 
              : 'bg-blue-600 text-white hover:bg-blue-500'
          }`}
          style={{ minWidth: '44px', minHeight: '44px' }} // Touch target
        >
          {showEditor ? <X size={18} /> : <FileJson size={18} />}
          <span className="hidden sm:inline">{showEditor ? 'Close Input' : 'Import JSON'}</span>
        </button>
      </div>
    </div>
  );
};

import React from 'react';

interface JsonEditorProps {
  value: string;
  onChange: (val: string) => void;
  isOpen: boolean;
}

export const JsonEditor: React.FC<JsonEditorProps> = ({ value, onChange, isOpen }) => {
  if (!isOpen) return null;

  return (
    <div className="absolute top-14 right-0 bottom-0 w-full sm:w-[400px] bg-neutral-900 border-l border-neutral-800 shadow-2xl z-40 flex flex-col transition-transform duration-300">
      <div className="p-3 bg-neutral-800/50 border-b border-neutral-800 text-xs text-neutral-400">
        Paste AI-generated JSON schema below. The graph updates automatically.
      </div>
      <textarea
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className="flex-1 w-full bg-[#1e1e1e] text-neutral-300 p-4 font-mono text-xs resize-none outline-none focus:ring-1 focus:ring-blue-500/50"
        spellCheck={false}
        placeholder='{ "nodes": [], "connections": [] }'
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { GraphCanvas } from './components/NodeGraph/GraphCanvas';
import { Toolbar } from './components/UI/Toolbar';
import { JsonEditor } from './components/UI/JsonEditor';
import { parseGraphJSON } from './utils';
import { DEFAULT_JSON_EXAMPLE } from './constants';
import { GraphSchema } from './types';

function App() {
  const [jsonInput, setJsonInput] = useState<string>(DEFAULT_JSON_EXAMPLE);
  const [schema, setSchema] = useState<GraphSchema | null>(null);
  const [parseError, setParseError] = useState<string | null>(null);
  const [showEditor, setShowEditor] = useState<boolean>(false); // Hidden by default on mobile load, handy on desktop

  // Parse JSON whenever input changes
  useEffect(() => {
    const { schema: parsedSchema, error } = parseGraphJSON(jsonInput);
    if (parsedSchema) {
      setSchema(parsedSchema);
      setParseError(null);
    } else {
      setParseError(error);
    }
  }, [jsonInput]);

  // Initial responsive check
  useEffect(() => {
    if (window.innerWidth > 768) {
        setShowEditor(true);
    }
  }, []);

  return (
    <div className="w-screen h-screen flex flex-col bg-neutral-900 overflow-hidden text-neutral-200 font-sans">
      <Toolbar 
        onToggleEditor={() => setShowEditor(!showEditor)} 
        showEditor={showEditor}
        hasError={!!parseError}
      />

      <div className="flex-1 relative">
        {/* Canvas Area */}
        <div className="absolute inset-0 z-0">
            {schema ? (
                <GraphCanvas schema={schema} />
            ) : (
                <div className="w-full h-full flex items-center justify-center text-neutral-600 flex-col gap-4">
                    <p>No valid graph data.</p>
                </div>
            )}
        </div>

        {/* Editor Overlay */}
        <JsonEditor 
            value={jsonInput} 
            onChange={setJsonInput} 
            isOpen={showEditor} 
        />

        {/* Error Toast */}
        {parseError && (
          <div className="absolute bottom-6 left-1/2 transform -translate-x-1/2 bg-red-900/90 text-red-100 px-4 py-2 rounded-lg shadow-lg text-sm border border-red-700 z-50 max-w-[90vw]">
            Error: {parseError}
          </div>
        )}
      </div>
    </div>
  );
}

