  // 1. Header height
  // 2. Body padding-top (p-2 = 8px)
  // 3. Properties height + their inter-element gaps
  // 4. Row margin-top (mt-1 = 4px)
  // 5. Port index height + inter-port gaps
  // 6. Half height of the port row to reach center (h-6 = 24px / 2 = 12px)

  const paddingY = 8; // From p-2
  const rowGap = 4;   // From gap-1
  const mt1 = 4;      // From mt-1

  let currentY = UI_SIZES.HEADER_HEIGHT + paddingY;

  if (node.properties && node.properties.length > 0) {
    // Each property adds height + a gap following it
    currentY += node.properties.length * (UI_SIZES.PROPERTY_HEIGHT + rowGap);
  }

  // Account for the mt-1 on the port container row
  currentY += mt1;

  // Calculate port vertical offset (each port + its following gap)
  const portYOffset = index * (UI_SIZES.PORT_HEIGHT + rowGap) + (UI_SIZES.PORT_HEIGHT / 2);

  // Requested shift: move UP by 120% of the port dot radius
  const verticalShift = UI_SIZES.PORT_RADIUS * 1.2;

  const y = node.position.y + currentY + portYOffset - verticalShift;

  const x = type === 'input' 
    ? node.position.x 
    : node.position.x + node.size.width;

  return { x, y };
};

// --- Connection Path ---

export const calculateBezierPath = (
  x1: number,
  y1: number,
  x2: number,
  y2: number
): string => {
  const dist = Math.abs(x2 - x1) * 0.5; // Curvature strength
  const cp1x = x1 + Math.max(dist, 50); 
  const cp1y = y1;
  const cp2x = x2 - Math.max(dist, 50);
  const cp2y = y2;

  return `M ${x1} ${y1} C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${x2} ${y2}`;
};

// --- Parsing ---

export const parseGraphJSON = (json: string): { schema: GraphSchema | null; error: string | null } => {
  try {
    const parsed = JSON.parse(json);
    if (!parsed.nodes || !Array.isArray(parsed.nodes)) {
      return { schema: null, error: "Invalid JSON: 'nodes' array missing." };
    }
    parsed.connections = parsed.connections || [];
    return { schema: parsed as GraphSchema, error: null };
  } catch (e: any) {
    return { schema: null, error: e.message || "Invalid JSON syntax." };
  }
};

import { TYPE_COLORS, UI_SIZES } from './constants';
import { DataType, GraphSchema, NodeData } from './types';

// --- Color Helpers ---

export const getPortColor = (type: DataType): string => {
  return TYPE_COLORS[type.toLowerCase()] || TYPE_COLORS.float; // Default to grey/float if unknown
};

export const isValidVector3 = (val: any): boolean => {
  return Array.isArray(val) && val.length === 3 && val.every(n => typeof n === 'number');
};

export const isValidColor = (val: any): boolean => {
  // Blender usually sends [R, G, B] or [R, G, B, A]
  return Array.isArray(val) && (val.length === 3 || val.length === 4) && val.every(n => typeof n === 'number');
};

export const formatVector = (val: number[]): string => {
  return `[${val.map(n => n.toFixed(2)).join(', ')}]`;
};

// --- Geometry Helpers ---

/**
 * Calculates the absolute position of a port within the global canvas space.
 * Used for drawing connection lines.
 */
export const getPortPosition = (
  node: NodeData,
  portId: string,
  type: 'input' | 'output'
): { x: number; y: number } | null => {

  const ports = type === 'input' ? node.inputs : node.outputs;
  if (!ports) return null;

  const index = ports.findIndex(p => p.id === portId);
  if (index === -1) return null;

  // Constants matching NodeWidget Tailwind classes
  const HEADER_H = 32; // Matches h-8 in NodeWidget
  const PADDING_TOP = 8; // p-2
  const GAP = 4; // gap-1
  const PROP_H = 28; // h-7
  const PORT_H = 24; // h-6

  // Base offset: Header + Top Padding
  let currentY = HEADER_H + PADDING_TOP;

  // Properties: Each property takes space + a gap
  const numProps = node.properties?.length || 0;
  if (numProps > 0) {
    currentY += numProps * (PROP_H + GAP);
  }

  // The Ports Row container is another child in the flex-col gap-1.
  // We removed 'mt-1' from NodeWidget to make this simple: it's just another child after a gap.
  // Calculation for center of port at 'index':
  // (Height of port rows above) + (Gaps between them) + (Half height of current port)
  const portYInContainer = index * (PORT_H + GAP) + (PORT_H / 2);

  // Total base Y (the exact center of the port dot)
  const baseY = node.position.y + currentY + portYInContainer;

  // The user requested to move them UP by 120% of the port dot radius (5 * 1.2 = 6px)
  const verticalShift = UI_SIZES.PORT_RADIUS * 1.2;

  const y = baseY - verticalShift;

  const x = type === 'input' 
    ? node.position.x 
    : node.position.x + node.size.width;

  return { x, y };
};

// --- Connection Path ---

export const calculateBezierPath = (
  x1: number,
  y1: number,
  x2: number,
  y2: number
): string => {
  const dist = Math.abs(x2 - x1) * 0.5; // Curvature strength
  const cp1x = x1 + Math.max(dist, 50); 
  const cp1y = y1;
  const cp2x = x2 - Math.max(dist, 50);
  const cp2y = y2;

  return `M ${x1} ${y1} C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${x2} ${y2}`;
};

