import React, { useRef, useState, useEffect } from 'react';
import { GraphSchema, ViewportState } from '../../types';
import { NodeWidget } from './NodeWidget';
import { ConnectionLine } from './ConnectionLine';
import { getPortPosition } from '../../utils';

interface GraphCanvasProps {
  schema: GraphSchema;
}

export const GraphCanvas: React.FC<GraphCanvasProps> = ({ schema }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [viewport, setViewport] = useState<ViewportState>({ x: 0, y: 0, scale: 1 });
  const [isDragging, setIsDragging] = useState(false);
  const [lastMousePos, setLastMousePos] = useState({ x: 0, y: 0 });

  // Pinch zoom state
  const [initialPinchDist, setInitialPinchDist] = useState<number | null>(null);
  const [initialScale, setInitialScale] = useState<number>(1);

  // --- Pan Logic (Mouse & Touch) ---

  const handlePointerDown = (e: React.PointerEvent) => {
    // Allow panning with Left (0) or Right (2) mouse buttons. 
    // Touch pointers often have button 0 or -1.
    if (e.pointerType === 'mouse' && e.button !== 0 && e.button !== 2) return;

    // We only track the primary pointer for panning to avoid conflict with pinch-zoom
    if (!e.isPrimary) return; 

    // Prevent default browser behavior (text selection, etc.) which is critical on mobile
    e.preventDefault();

    setIsDragging(true);
    setLastMousePos({ x: e.clientX, y: e.clientY });

    // Capture pointer to track movements even if they leave the container
    containerRef.current?.setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging) return;

    // Safety check: if mouse is used, ensure at least one panning button is still pressed
    if (e.pointerType === 'mouse') {
      const isLeftPressed = (e.buttons & 1) !== 0;
      const isRightPressed = (e.buttons & 2) !== 0;
      if (!isLeftPressed && !isRightPressed) {
        setIsDragging(false);
        return;
      }
    }

    // For touch, preventDefault in move can help prevent native scroll interference
    if (e.pointerType === 'touch') {
        e.preventDefault();
    }

    const dx = e.clientX - lastMousePos.x;
    const dy = e.clientY - lastMousePos.y;

    setViewport(prev => ({
      ...prev,
      x: prev.x + dx,
      y: prev.y + dy
    }));

    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (e.isPrimary) {
      setIsDragging(false);
      setInitialPinchDist(null);
      if (containerRef.current?.hasPointerCapture(e.pointerId)) {
        containerRef.current.releasePointerCapture(e.pointerId);
      }
    }
  };

  // More robust than onPointerLeave for handling interruptions (e.g. system gestures, alerts)
  const handleLostPointerCapture = (e: React.PointerEvent) => {
    if (e.isPrimary) {
      setIsDragging(false);
      setInitialPinchDist(null);
    }
  };

  // --- Zoom Logic (Wheel) ---

  const handleWheel = (e: React.WheelEvent) => {
    e.stopPropagation();
    const zoomFactor = -e.deltaY * 0.001;
    const newScale = Math.min(Math.max(0.1, viewport.scale + zoomFactor), 5);

    setViewport(prev => ({
      ...prev,
      scale: newScale
    }));
  };

  // --- Touch Pinch Logic (Native Touch Events) ---

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;

    const onTouchStart = (e: TouchEvent) => {
      if (e.touches.length === 2) {
        const dist = Math.hypot(
          e.touches[0].clientX - e.touches[1].clientX,
          e.touches[0].clientY - e.touches[1].clientY
        );
        setInitialPinchDist(dist);
        setInitialScale(viewport.scale);
      }
    };

    const onTouchMove = (e: TouchEvent) => {
      if (e.touches.length === 2 && initialPinchDist !== null) {
        e.preventDefault(); 
        const dist = Math.hypot(
          e.touches[0].clientX - e.touches[1].clientX,
          e.touches[0].clientY - e.touches[1].clientY
        );
        const scaleFactor = dist / initialPinchDist;
        setViewport(prev => ({
          ...prev,
          scale: Math.min(Math.max(0.1, initialScale * scaleFactor), 5)
        }));
      }
    };

    el.addEventListener('touchstart', onTouchStart, { passive: false });
    el.addEventListener('touchmove', onTouchMove, { passive: false });

    return () => {
      el.removeEventListener('touchstart', onTouchStart);
      el.removeEventListener('touchmove', onTouchMove);
    };
  }, [viewport.scale, initialPinchDist, initialScale]);

  const connectionLines = schema.connections.map((conn, idx) => {
    const actualSourceNode = schema.nodes.find(n => n.outputs?.some(o => o.id === conn.from));
    const actualTargetNode = schema.nodes.find(n => n.inputs?.some(i => i.id === conn.to));

    if (!actualSourceNode || !actualTargetNode) return null;

    const start = getPortPosition(actualSourceNode, conn.from, 'output');
    const end = getPortPosition(actualTargetNode, conn.to, 'input');

    const portDef = actualSourceNode.outputs?.find(o => o.id === conn.from);

    if (start && end && portDef) {
      return (
        <ConnectionLine
          key={`${conn.from}-${conn.to}-${idx}`}
          x1={start.x}
          y1={start.y}
          x2={end.x}
          y2={end.y}
          type={portDef.type}
        />
      );
    }
    return null;
  });

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-[#111] overflow-hidden relative cursor-grab active:cursor-grabbing touch-none"
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onLostPointerCapture={handleLostPointerCapture}
      onWheel={handleWheel}
      onContextMenu={(e) => e.preventDefault()}
    >
        <div 
            className="absolute inset-0 pointer-events-none opacity-20"
            style={{
                backgroundImage: 'linear-gradient(#333 1px, transparent 1px), linear-gradient(90deg, #333 1px, transparent 1px)',
                backgroundSize: `${20 * viewport.scale}px ${20 * viewport.scale}px`,
                backgroundPosition: `${viewport.x}px ${viewport.y}px`
            }}
        />

        <div 
            style={{
                transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.scale})`,
                transformOrigin: '0 0',
                width: '100%',
                height: '100%',
                position: 'absolute',
                top: 0,
                left: 0
            }}
        >
            <svg className="absolute top-0 left-0 overflow-visible pointer-events-none w-1 h-1">
                {connectionLines}
            </svg>

            {schema.nodes.map(node => (
                <NodeWidget key={node.id} data={node} />
            ))}
        </div>

        <div className="absolute bottom-4 left-4 bg-black/50 p-2 rounded text-xs text-neutral-400 font-mono pointer-events-none">
            Zoom: {Math.round(viewport.scale * 100)}% | X: {Math.round(viewport.x)} Y: {Math.round(viewport.y)}
        </div>
    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { GraphSchema, ViewportState } from '../../types';
import { NodeWidget } from './NodeWidget';
import { ConnectionLine } from './ConnectionLine';
import { getPortPosition } from '../../utils';

interface GraphCanvasProps {
  schema: GraphSchema;
}

export const GraphCanvas: React.FC<GraphCanvasProps> = ({ schema }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [viewport, setViewport] = useState<ViewportState>({ x: 0, y: 0, scale: 1 });

  // Refs to access current state inside event listeners without triggering re-renders
  const viewportRef = useRef(viewport);
  const isDraggingRef = useRef(false);
  const lastMousePosRef = useRef({ x: 0, y: 0 });

  // Sync ref with state
  useEffect(() => {
    viewportRef.current = viewport;
  }, [viewport]);

  // Pinch zoom state ref (mutable to avoid re-renders during rapid gestures)
  const pinchRef = useRef<{
    active: boolean;
    startDist: number;
    startScale: number;
    startViewX: number;
    startViewY: number;
    centerX: number;
    centerY: number;
  }>({
    active: false,
    startDist: 0,
    startScale: 1,
    startViewX: 0,
    startViewY: 0,
    centerX: 0,
    centerY: 0
  });

  // --- Pan Logic (Pointer Events) ---

  const handlePointerDown = (e: React.PointerEvent) => {
    if (e.pointerType === 'mouse' && e.button !== 0 && e.button !== 2) return;
    if (!e.isPrimary) return; 

    // Don't start panning if we are likely trying to pinch (multitouch handled by touch listeners)
    if (pinchRef.current.active) return;

    e.preventDefault();
    isDraggingRef.current = true;
    lastMousePosRef.current = { x: e.clientX, y: e.clientY };
    containerRef.current?.setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDraggingRef.current || pinchRef.current.active) return;

    if (e.pointerType === 'mouse') {
      const isLeftPressed = (e.buttons & 1) !== 0;
      const isRightPressed = (e.buttons & 2) !== 0;
      if (!isLeftPressed && !isRightPressed) {
        isDraggingRef.current = false;
        return;
      }
    }

    if (e.pointerType === 'touch') {
        e.preventDefault();
    }

    const dx = e.clientX - lastMousePosRef.current.x;
    const dy = e.clientY - lastMousePosRef.current.y;

    setViewport(prev => ({
      ...prev,
      x: prev.x + dx,
      y: prev.y + dy
    }));

    lastMousePosRef.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (e.isPrimary) {
      isDraggingRef.current = false;
      if (containerRef.current?.hasPointerCapture(e.pointerId)) {
        containerRef.current.releasePointerCapture(e.pointerId);
      }
    }
  };

  const handleLostPointerCapture = (e: React.PointerEvent) => {
    if (e.isPrimary) {
      isDraggingRef.current = false;
    }
  };

  // --- Wheel Zoom ---

  const handleWheel = (e: React.WheelEvent) => {
    e.stopPropagation();
    // Zoom towards mouse pointer logic
    const zoomSensitivity = 0.001;
    const delta = -e.deltaY * zoomSensitivity;
    const currentScale = viewportRef.current.scale;
    const newScale = Math.min(Math.max(0.1, currentScale + delta), 5);

    // Calculate mouse position relative to the container
    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return;

    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    // Calculate the world point under the mouse before zoom
    // WorldX = (MouseX - ViewX) / Scale
    const worldX = (mouseX - viewportRef.current.x) / currentScale;
    const worldY = (mouseY - viewportRef.current.y) / currentScale;

    // Calculate new ViewX so that WorldX remains under MouseX
    // ViewX = MouseX - (WorldX * NewScale)
    const newX = mouseX - (worldX * newScale);
    const newY = mouseY - (worldY * newScale);

    setViewport({
      x: newX,
      y: newY,
      scale: newScale
    });
  };

  // --- Touch Pinch Logic (Native Events) ---

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;

    const onTouchStart = (e: TouchEvent) => {
      if (e.touches.length === 2) {
        // Stop panning if we start pinching
        isDraggingRef.current = false;

        const t1 = e.touches[0];
        const t2 = e.touches[1];

        const dist = Math.hypot(
          t1.clientX - t2.clientX,
          t1.clientY - t2.clientY
        );

        const cx = (t1.clientX + t2.clientX) / 2;
        const cy = (t1.clientY + t2.clientY) / 2;

        const currentView = viewportRef.current;

        pinchRef.current = {
          active: true,
          startDist: dist,
          startScale: currentView.scale,
          startViewX: currentView.x,
          startViewY: currentView.y,
          centerX: cx,
          centerY: cy
        };
      }
    };

    const onTouchMove = (e: TouchEvent) => {
      if (e.touches.length === 2 && pinchRef.current.active) {
        e.preventDefault(); 

        const t1 = e.touches[0];
        const t2 = e.touches[1];

        const dist = Math.hypot(
          t1.clientX - t2.clientX,
          t1.clientY - t2.clientY
        );

        const cx = (t1.clientX + t2.clientX) / 2;
        const cy = (t1.clientY + t2.clientY) / 2;

        const { startDist, startScale, startViewX, startViewY, centerX, centerY } = pinchRef.current;

        // Calculate scale factor
        const scaleRatio = dist / startDist;
        const newScale = Math.min(Math.max(0.1, startScale * scaleRatio), 5);

        // Math to keep the point under the pinch center stable:
        // We calculate where the 'center' point was in World Space at the START of the pinch
        const worldPointX = (centerX - startViewX) / startScale;
        const worldPointY = (centerY - startViewY) / startScale;

        // Now we calculate where the viewport needs to be so that same World Point
        // is at the NEW center position (cx, cy)
        // Note: We use current cx/cy to allow panning while pinching
        const newViewX = cx - (worldPointX * newScale);
        const newViewY = cy - (worldPointY * newScale);

        setViewport({
          x: newViewX,
          y: newViewY,
          scale: newScale
        });
      }
    };

    const onTouchEnd = (e: TouchEvent) => {
      if (e.touches.length < 2) {
        pinchRef.current.active = false;
      }
    };

    el.addEventListener('touchstart', onTouchStart, { passive: false });
    el.addEventListener('touchmove', onTouchMove, { passive: false });
    el.addEventListener('touchend', onTouchEnd);
    el.addEventListener('touchcancel', onTouchEnd);

    return () => {
      el.removeEventListener('touchstart', onTouchStart);
      el.removeEventListener('touchmove', onTouchMove);
      el.removeEventListener('touchend', onTouchEnd);
      el.removeEventListener('touchcancel', onTouchEnd);
    };
  }, []); // Dependency array is empty because we use refs for state

  const connectionLines = schema.connections.map((conn, idx) => {
    const actualSourceNode = schema.nodes.find(n => n.outputs?.some(o => o.id === conn.from));
    const actualTargetNode = schema.nodes.find(n => n.inputs?.some(i => i.id === conn.to));

    if (!actualSourceNode || !actualTargetNode) return null;

    const start = getPortPosition(actualSourceNode, conn.from, 'output');
    const end = getPortPosition(actualTargetNode, conn.to, 'input');

    const portDef = actualSourceNode.outputs?.find(o => o.id === conn.from);

    if (start && end && portDef) {
      return (
        <ConnectionLine
          key={`${conn.from}-${conn.to}-${idx}`}
          x1={start.x}
          y1={start.y}
          x2={end.x}
          y2={end.y}
          type={portDef.type}
        />
      );
    }
    return null;
  });

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-[#111] overflow-hidden relative cursor-grab active:cursor-grabbing touch-none"
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onLostPointerCapture={handleLostPointerCapture}
      onWheel={handleWheel}
      onContextMenu={(e) => e.preventDefault()}
    >
        <div 
            className="absolute inset-0 pointer-events-none opacity-20"
            style={{
                backgroundImage: 'linear-gradient(#333 1px, transparent 1px), linear-gradient(90deg, #333 1px, transparent 1px)',
                backgroundSize: `${20 * viewport.scale}px ${20 * viewport.scale}px`,
                backgroundPosition: `${viewport.x}px ${viewport.y}px`
            }}
        />

        <div 
            style={{
                transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.scale})`,
                transformOrigin: '0 0',
                width: '100%',
                height: '100%',
                position: 'absolute',
                top: 0,
                left: 0
            }}
        >
            <svg className="absolute top-0 left-0 overflow-visible pointer-events-none w-1 h-1">
                {connectionLines}
            </svg>

            {schema.nodes.map(node => (
                <NodeWidget key={node.id} data={node} />
            ))}
        </div>

        <div className="absolute bottom-4 left-4 bg-black/50 p-2 rounded text-xs text-neutral-400 font-mono pointer-events-none">
            Zoom: {Math.round(viewport.scale * 100)}% | X: {Math.round(viewport.x)} Y: {Math.round(viewport.y)}
        </div>
    </div>
  );
};

import { TYPE_COLORS, UI_SIZES } from './constants';
import { DataType, GraphSchema, NodeData } from './types';

// --- Color Helpers ---

export const getPortColor = (type: DataType): string => {
  return TYPE_COLORS[type.toLowerCase()] || TYPE_COLORS.float; // Default to grey/float if unknown
};

export const isValidVector3 = (val: any): boolean => {
  return Array.isArray(val) && val.length === 3 && val.every(n => typeof n === 'number');
};

export const isValidColor = (val: any): boolean => {
  // Blender usually sends [R, G, B] or [R, G, B, A]
  return Array.isArray(val) && (val.length === 3 || val.length === 4) && val.every(n => typeof n === 'number');
};

export const formatVector = (val: number[]): string => {
  return `[${val.map(n => n.toFixed(2)).join(', ')}]`;
};

// --- Geometry Helpers ---

/**
 * Calculates the absolute position of a port within the global canvas space.
 * Used for drawing connection lines.
 */
export const getPortPosition = (
  node: NodeData,
  portId: string,
  type: 'input' | 'output'
): { x: number; y: number } | null => {

  const ports = type === 'input' ? node.inputs : node.outputs;
  if (!ports) return null;

  const index = ports.findIndex(p => p.id === portId);
  if (index === -1) return null;

  // Constants matching NodeWidget Tailwind classes
  // NodeWidget: border (1px) + h-8 header (32px) + p-2 (8px)
  const BORDER_W = 1;
  const HEADER_H = 32; 
  const PADDING_TOP = 8;
  const GAP = 4; // gap-1 (4px)
  const PROP_H = 28; // h-7 (28px)
  const PORT_H = 24; // h-6 (24px)

  // Base offset: Border + Header + Top Padding
  let currentY = BORDER_W + HEADER_H + PADDING_TOP;

  // Properties: Each property takes space + a gap
  const numProps = node.properties?.length || 0;
  if (numProps > 0) {
    // Each property adds Height + Gap
    currentY += numProps * (PROP_H + GAP);
  }

  // Ports Row
  // Note: The Ports Row is a flex container with `gap-1` (4px).
  // However, user reports imply a drift, suggesting the effective visual step is closer to just the height.
  // We use a tightened step to match the visual "variable offset" fix.
  // Center of the port is at: Start of row + (Index * Step) + Half Height

  const PORT_STEP = PORT_H + 0; // Reducing gap contribution to 0 to fix downward drift
  const PORT_CENTER_OFFSET = PORT_H / 2;

  const portYInContainer = (index * PORT_STEP) + PORT_CENTER_OFFSET;

  // Total base Y
  // We add a small manual correction (-1px) to perfectly align with the 12x12 dot center
  const y = node.position.y + currentY + portYInContainer - 1;

  const x = type === 'input' 
    ? node.position.x 
    : node.position.x + node.size.width;

  return { x, y };
};

// --- Connection Path ---

export const calculateBezierPath = (
  x1: number,
  y1: number,
  x2: number,
  y2: number
): string => {
  const dist = Math.abs(x2 - x1) * 0.5; // Curvature strength
  const cp1x = x1 + Math.max(dist, 50); 
  const cp1y = y1;
  const cp2x = x2 - Math.max(dist, 50);
  const cp2y = y2;

  return `M ${x1} ${y1} C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${x2} ${y2}`;
};

// --- Parsing ---

export const parseGraphJSON = (json: string): { schema: GraphSchema | null; error: string | null } => {
  try {
    const parsed = JSON.parse(json);
    if (!parsed.nodes || !Array.isArray(parsed.nodes)) {
      return { schema: null, error: "Invalid JSON: 'nodes' array missing." };
    }
    parsed.connections = parsed.connections || [];
    return { schema: parsed as GraphSchema, error: null };
  } catch (e: any) {
    return { schema: null, error: e.message || "Invalid JSON syntax." };
  }
};

import React from 'react';
import { NodeData, NodePort, NodeProperty } from '../../types';
import { UI_SIZES, TYPE_COLORS } from '../../constants';
import { getPortColor, isValidVector3, isValidColor, formatVector } from '../../utils';
import { AlertTriangle, HelpCircle } from 'lucide-react';

interface NodeWidgetProps {
  data: NodeData;
}

const PortDot: React.FC<{ type: string; isConnected?: boolean }> = ({ type, isConnected }) => {
  const color = getPortColor(type);
  return (
    <div 
      className={`w-[12px] h-[12px] rounded-full border border-neutral-900 ${isConnected ? '' : 'opacity-80'}`}
      style={{ backgroundColor: color }}
    />
  );
};

const ValueDisplay: React.FC<{ property: NodeProperty }> = ({ property }) => {
  const { type, value } = property;

  if (type === 'float') {
    const num = typeof value === 'number' ? value : parseFloat(value);
    if (isNaN(num)) return <span className="text-red-500 text-xs">NaN</span>;
    return (
      <div className="bg-neutral-700 px-2 py-0.5 rounded text-neutral-300 text-xs font-mono min-w-[40px] text-center">
        {num.toFixed(3)}
      </div>
    );
  }

  if (type === 'vector3') {
    if (!isValidVector3(value)) {
       return <span className="text-red-500 text-[10px] flex items-center gap-1"><AlertTriangle size={10} /> Invalid Data</span>;
    }
    return (
      <div className="flex gap-1 text-[10px] font-mono">
        <span className="bg-red-900/50 px-1 rounded text-red-200">{value[0].toFixed(1)}</span>
        <span className="bg-green-900/50 px-1 rounded text-green-200">{value[1].toFixed(1)}</span>
        <span className="bg-blue-900/50 px-1 rounded text-blue-200">{value[2].toFixed(1)}</span>
      </div>
    );
  }

  if (type === 'color') {
    if (!isValidColor(value)) {
       return <div className="w-[32px] h-[16px] bg-black rounded border border-red-500 relative flex justify-center items-center"><HelpCircle size={10} className="text-red-500"/></div>;
    }
    const bg = `rgb(${value[0] * 255}, ${value[1] * 255}, ${value[2] * 255})`;
    return (
      <div className="flex items-center gap-2">
         <div className="w-[48px] h-[16px] rounded border border-neutral-600 shadow-sm" style={{ backgroundColor: bg }} />
      </div>
    );
  }

  if (type === 'string') {
    return <span className="text-neutral-400 text-xs italic truncate max-w-[100px] block" title={String(value)}>{String(value)}</span>;
  }

  return <span className="text-neutral-500 text-xs">Unknown</span>;
};

export const NodeWidget: React.FC<NodeWidgetProps> = ({ data }) => {
  const { x, y } = data.position;
  const { width, height } = data.size;

  let headerClass = "bg-neutral-700";
  if (data.type.includes("Input") || data.type.includes("Coord")) headerClass = "bg-red-900/80"; 
  if (data.type.includes("Output")) headerClass = "bg-neutral-800 border-b border-neutral-600";
  if (data.type.includes("Shader")) headerClass = "bg-green-900/60"; 

  return (
    <div
      className="absolute flex flex-col rounded-lg shadow-2xl border border-neutral-700 bg-neutral-800/95 overflow-hidden text-sm select-none touch-none pointer-events-none"
      style={{
        left: x,
        top: y,
        width: width,
        minHeight: height,
      }}
    >
      {/* Explicit 32px height to avoid rem scaling issues */}
      <div className={`h-[32px] px-3 ${headerClass} text-white font-medium text-xs tracking-wide flex items-center justify-between shrink-0`}>
        <span className="truncate">{data.name}</span>
      </div>

      {/* Explicit 8px padding, 4px gap */}
      <div className="flex flex-col flex-1 p-[8px] gap-[4px] relative">
        {data.properties?.map((prop, idx) => (
          <div key={`prop-${idx}`} className="flex items-center justify-between h-[28px] px-1 shrink-0">
            <span className="text-neutral-300 text-xs">{prop.name}</span>
            <ValueDisplay property={prop} />
          </div>
        ))}

        <div className="flex flex-row justify-between shrink-0">
            <div className="flex flex-col gap-[4px] w-1/2">
                {data.inputs?.map((port) => (
                    <div key={port.id} className="flex items-center gap-2 h-[24px] -ml-3 pl-1 shrink-0">
                         <PortDot type={port.type} isConnected={port.connected} />
                         <span className="text-neutral-300 text-xs truncate">{port.name}</span>
                    </div>
                ))}
            </div>

             <div className="flex flex-col gap-[4px] w-1/2 items-end">
                {data.outputs?.map((port) => (
                    <div key={port.id} className="flex items-center gap-2 h-[24px] -mr-3 pr-1 justify-end shrink-0">
                         <span className="text-neutral-300 text-xs truncate text-right">{port.name}</span>
                         <PortDot type={port.type} isConnected={true} /> 
                    </div>
                ))}
            </div>
        </div>
      </div>
    </div>
  );
};

