  float: '#A1A1A1', // Grey
  vector3: '#6363C7', // Purple
  color: '#C7C729', // Yellow
  string: '#63C7C7', // Cyan/Blueish
  shader: '#63C763', // Green (Common in Blender)
  gradient: '#A1A1A1', // Gradient usually has grey inputs/widgets, visual handled by widget
  unknown: '#FF4444', // Red for errors
};

export const UI_SIZES = {
  HEADER_HEIGHT: 28, // Adjusted to match the py-1.5 + text-xs rendering
  PORT_HEIGHT: 24,
  PROPERTY_HEIGHT: 28,
  PORT_RADIUS: 5,
  NODE_PADDING_X: 12,
  NODE_PADDING_Y: 8,
  ROW_GAP: 4, // Represents 'gap-1' in Tailwind
};

