import { TYPE_COLORS, UI_SIZES } from './constants';
import { DataType, GraphSchema, NodeData } from './types';

// --- Color Helpers ---

export const getPortColor = (type: DataType): string => {
  return TYPE_COLORS[type.toLowerCase()] || TYPE_COLORS.float; // Default to grey/float if unknown
};

export const isValidVector3 = (val: any): boolean => {
  return Array.isArray(val) && val.length === 3 && val.every(n => typeof n === 'number');
};

export const isValidColor = (val: any): boolean => {
  // Blender usually sends [R, G, B] or [R, G, B, A]
  return Array.isArray(val) && (val.length === 3 || val.length === 4) && val.every(n => typeof n === 'number');
};

export const isValidGradient = (val: any): boolean => {
  // Expecting array of { pos: number, color: number[] }
  if (!Array.isArray(val)) return false;
  return val.every(stop => 
    typeof stop === 'object' && 
    stop !== null && 
    typeof stop.pos === 'number' && 
    isValidColor(stop.color)
  );
};

export const rgbToHex = (color: number[]): string => {
  const toHex = (c: number) => {
    const hex = Math.round(Math.max(0, Math.min(1, c)) * 255).toString(16);
    return hex.length === 1 ? '0' + hex : hex;
  };
  return `#${toHex(color[0])}${toHex(color[1])}${toHex(color[2])}`;
};

export const generateGradientCSS = (stops: any[]): string => {
  if (!stops || stops.length === 0) return '#4b4b4b'; // Fallback grey

  // Sort by position
  const sorted = [...stops].sort((a, b) => a.pos - b.pos);

  const cssStops = sorted.map(stop => {
    // Clamp pos 0-1
    const pos = Math.max(0, Math.min(1, stop.pos)) * 100;
    const [r, g, b] = stop.color;
    // Blender colors are 0-1 linear, convert to 0-255
    const c = `rgb(${Math.round(r * 255)}, ${Math.round(g * 255)}, ${Math.round(b * 255)})`;
    return `${c} ${pos}%`;
  });

  return `linear-gradient(90deg, ${cssStops.join(', ')})`;
};

export const formatVector = (val: number[]): string => {
  return `[${val.map(n => n.toFixed(2)).join(', ')}]`;
};

// --- Geometry Helpers ---

/**
 * Calculates the absolute position of a port within the global canvas space.
 * Used for drawing connection lines.
 */
export const getPortPosition = (
  node: NodeData,
  portId: string,
  type: 'input' | 'output'
): { x: number; y: number } | null => {

  const ports = type === 'input' ? node.inputs : node.outputs;
  if (!ports) return null;

  const index = ports.findIndex(p => p.id === portId);
  if (index === -1) return null;

  // Constants matching NodeWidget explicit pixel classes exactly
  const BORDER_W = 1;
  const HEADER_H = 32; // h-[32px]
  const PADDING_TOP = 8; // p-[8px]
  const GAP = 4; // gap-[4px]
  const PROP_H = 28; // h-[28px]
  const PORT_H = 24; // h-[24px]

  // Base offset to start of content area
  let currentY = BORDER_W + HEADER_H + PADDING_TOP;

  // Properties Section
  const numProps = node.properties?.length || 0;
  if (numProps > 0) {
    // We can't strictly assume fixed height anymore because Gradient nodes expand
    // But for port calculation (which is usually separate from props), we might need logic update
    // if props push ports down.
    // However, in the NodeWidget structure:
    // Header -> Props -> Ports.
    // So dynamic prop height DOES affect port Y.
    // NOTE: This simple calculator assumes standard PROP_H. 
    // If we have variable height properties (like expanded gradient), this calc needs to be smarter.
    // For now, we will assume standard height for calculation or accept slight offset on complex nodes.

    // To fix this properly, we'd need to measure DOM or store heights in schema. 
    // Given the constraints, we will iterate properties and add extra height for gradients.

    let propsHeight = 0;
    node.properties.forEach(p => {
       if (p.type === 'gradient') {
           propsHeight += 56; // 28px header + 24px extra details + padding
       } else {
           propsHeight += PROP_H;
       }
       propsHeight += GAP;
    });
    currentY += propsHeight;
  }

  // Ports Row
  const PORT_STEP = PORT_H + GAP; 
  const PORT_CENTER_OFFSET = PORT_H / 2;

  const portYInContainer = (index * PORT_STEP) + PORT_CENTER_OFFSET;

  // Total base Y
  const y = node.position.y + currentY + portYInContainer;

  const x = type === 'input' 
    ? node.position.x 
    : node.position.x + node.size.width;

  return { x, y };
};

// --- Connection Path ---

export const calculateBezierPath = (
  x1: number,
  y1: number,
  x2: number,
  y2: number
): string => {
  const dist = Math.abs(x2 - x1) * 0.5; // Curvature strength
  const cp1x = x1 + Math.max(dist, 50); 
  const cp1y = y1;
  const cp2x = x2 - Math.max(dist, 50);
  const cp2y = y2;

  return `M ${x1} ${y1} C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${x2} ${y2}`;
};

// --- Parsing ---

export const parseGraphJSON = (json: string): { schema: GraphSchema | null; error: string | null } => {
  try {
    const parsed = JSON.parse(json);
    if (!parsed.nodes || !Array.isArray(parsed.nodes)) {
      return { schema: null, error: "Invalid JSON: 'nodes' array missing." };
    }
    parsed.connections = parsed.connections || [];
    return { schema: parsed as GraphSchema, error: null };
  } catch (e: any) {
    return { schema: null, error: e.message || "Invalid JSON syntax." };
  }
};

import React, { useState } from 'react';
import { NodeData, NodeProperty } from '../../types';
import { getPortColor, isValidVector3, isValidColor, isValidGradient, generateGradientCSS, rgbToHex } from '../../utils';
import { AlertTriangle, HelpCircle, Check, Copy, ChevronDown } from 'lucide-react';

interface NodeWidgetProps {
  data: NodeData;
}

// Helper for Copy Logic
const useCopyFeedback = () => {
  const [copied, setCopied] = useState(false);

  const handleCopy = (text: string, e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 1500);
  };

  return { copied, handleCopy };
};

const PortDot: React.FC<{ type: string; isConnected?: boolean }> = ({ type, isConnected }) => {
  const color = getPortColor(type);
  return (
    <div 
      className={`w-[12px] h-[12px] rounded-full border border-neutral-900 ${isConnected ? '' : 'opacity-80'}`}
      style={{ backgroundColor: color }}
    />
  );
};

// --- Gradient Specific Component ---
const GradientDisplay: React.FC<{ value: any }> = ({ value }) => {
  const { copied, handleCopy } = useCopyFeedback();
  const [selectedStopIndex, setSelectedStopIndex] = useState<number>(0);

  const valid = isValidGradient(value);
  const background = valid ? generateGradientCSS(value) : '#4b4b4b';

  if (!valid) {
    return (
      <div className="flex-1 ml-2 h-[16px] rounded border border-neutral-600 shadow-sm relative overflow-hidden bg-neutral-800 flex items-center justify-center">
         <span className="text-[8px] text-neutral-400">Invalid Gradient</span>
      </div>
    );
  }

  const stops = value as Array<{ pos: number, color: number[] }>;
  const selectedStop = stops[selectedStopIndex] || stops[0];
  const selectedColorHex = rgbToHex(selectedStop.color);

  return (
    <div className="flex-1 ml-2 flex flex-col gap-1 pointer-events-auto">
       {/* Gradient Bar with Markers */}
      <div className="h-[16px] rounded border border-neutral-600 shadow-sm relative" style={{ background }}>
         {stops.map((stop, idx) => {
            const isSelected = idx === selectedStopIndex;
            return (
                <div 
                    key={idx}
                    onClick={(e) => { e.stopPropagation(); setSelectedStopIndex(idx); }}
                    className={`absolute top-0 w-0 h-full border-l-2 cursor-pointer hover:border-white transition-colors z-10 ${isSelected ? 'border-white z-20' : 'border-black/40'}`}
                    style={{ left: `${Math.max(0, Math.min(1, stop.pos)) * 100}%` }}
                >
                    <div className={`absolute -top-[4px] -left-[3px] w-0 h-0 border-l-[3px] border-r-[3px] border-t-[4px] border-l-transparent border-r-transparent ${isSelected ? 'border-t-white' : 'border-t-black/60'}`} />
                </div>
            )
         })}
      </div>

      {/* Selected Stop Details */}
      <div className="flex items-center gap-1 h-[20px] bg-neutral-900/50 rounded px-1 border border-neutral-700/50">

         {/* Position Input Look-alike */}
         <div 
            className="flex items-center gap-1 px-1 hover:bg-neutral-700/50 rounded cursor-pointer group"
            onClick={(e) => handleCopy(selectedStop.pos.toString(), e)}
            title="Click to copy position"
         >
             <span className="text-[9px] text-neutral-500 font-mono">Pos:</span>
             <span className="text-[10px] text-neutral-300 font-mono">{selectedStop.pos.toFixed(3)}</span>
         </div>

         <div className="w-[1px] h-[10px] bg-neutral-700 mx-1"/>

         {/* Color Input Look-alike */}
         <div 
            className="flex items-center gap-1 px-1 hover:bg-neutral-700/50 rounded cursor-pointer group flex-1"
            onClick={(e) => handleCopy(JSON.stringify(selectedStop.color), e)}
            title="Click to copy color array"
         >
             <div className="w-[8px] h-[8px] rounded-sm border border-neutral-600" style={{ backgroundColor: selectedColorHex }} />
             <span className="text-[10px] text-neutral-300 font-mono">{selectedColorHex}</span>
             {copied && <Check size={10} className="text-green-500 ml-auto" />}
         </div>
      </div>
    </div>
  );
};


const ValueDisplay: React.FC<{ property: NodeProperty }> = ({ property }) => {
  const { type, value } = property;
  const { copied, handleCopy } = useCopyFeedback();

  // Common wrapper for pointer events
  const Wrapper = ({ children, copyValue, className = "" }: any) => (
    <div 
        onClick={(e) => handleCopy(copyValue || JSON.stringify(value), e)}
        className={`pointer-events-auto cursor-pointer hover:brightness-110 active:scale-95 transition-all relative group ${className}`}
        title="Click to copy"
    >
        {children}
        {copied && (
            <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-black/90 text-green-400 text-[9px] px-1.5 py-0.5 rounded border border-green-900 shadow-lg whitespace-nowrap z-50 animate-in fade-in zoom-in duration-200">
                Copied!
            </div>
        )}
    </div>
  );

  if (type === 'float') {
    const num = typeof value === 'number' ? value : parseFloat(value);
    if (isNaN(num)) return <span className="text-red-500 text-xs">NaN</span>;
    return (
      <Wrapper copyValue={num.toString()}>
        <div className="bg-neutral-700 px-2 py-0.5 rounded text-neutral-300 text-xs font-mono min-w-[40px] text-center border border-transparent hover:border-neutral-500">
            {num.toFixed(3)}
        </div>
      </Wrapper>
    );
  }

  if (type === 'vector3') {
    if (!isValidVector3(value)) {
       return <span className="text-red-500 text-[10px] flex items-center gap-1"><AlertTriangle size={10} /> Invalid Data</span>;
    }
    return (
      <Wrapper copyValue={JSON.stringify(value)}>
        <div className="flex gap-1 text-[10px] font-mono border border-transparent p-0.5 rounded hover:border-neutral-600 bg-neutral-900/30">
            <span className="bg-red-900/50 px-1 rounded text-red-200">{value[0].toFixed(1)}</span>
            <span className="bg-green-900/50 px-1 rounded text-green-200">{value[1].toFixed(1)}</span>
            <span className="bg-blue-900/50 px-1 rounded text-blue-200">{value[2].toFixed(1)}</span>
        </div>
      </Wrapper>
    );
  }

  if (type === 'color') {
    if (!isValidColor(value)) {
       return <div className="w-[32px] h-[16px] bg-black rounded border border-red-500 relative flex justify-center items-center"><HelpCircle size={10} className="text-red-500"/></div>;
    }
    const bg = `rgb(${value[0] * 255}, ${value[1] * 255}, ${value[2] * 255})`;
    return (
      <Wrapper copyValue={JSON.stringify(value)}>
        <div className="flex items-center gap-2">
            <div className="w-[48px] h-[16px] rounded border border-neutral-600 shadow-sm" style={{ backgroundColor: bg }} />
        </div>
      </Wrapper>
    );
  }

  if (type === 'gradient') {
    return <GradientDisplay value={value} />;
  }

  if (type === 'string') {
    return (
      <Wrapper copyValue={String(value)}>
        <span className="text-neutral-400 text-xs italic truncate max-w-[100px] block hover:text-white" title={String(value)}>{String(value)}</span>
      </Wrapper>
    );
  }

  return <span className="text-neutral-500 text-xs">Unknown</span>;
};

export const NodeWidget: React.FC<NodeWidgetProps> = ({ data }) => {
  const { x, y } = data.position;
  const { width, height } = data.size;

  let headerClass = "bg-neutral-700";
  if (data.type.includes("Input") || data.type.includes("Coord")) headerClass = "bg-red-900/80"; 
  if (data.type.includes("Output")) headerClass = "bg-neutral-800 border-b border-neutral-600";
  if (data.type.includes("Shader")) headerClass = "bg-green-900/60"; 
  if (data.type.includes("ValToRGB")) headerClass = "bg-yellow-900/60"; // Color Ramp specific

  return (
    <div
      className="absolute flex flex-col rounded-lg shadow-2xl border border-neutral-700 bg-neutral-800/95 overflow-hidden text-sm select-none touch-none pointer-events-none"
      style={{
        left: x,
        top: y,
        width: width,
        minHeight: height,
      }}
    >
      {/* Header */}
      <div className={`h-[32px] px-3 ${headerClass} text-white font-medium text-xs tracking-wide flex items-center justify-between shrink-0`}>
        <span className="truncate">{data.name}</span>
      </div>

      {/* Body */}
      <div className="flex flex-col flex-1 p-[8px] gap-[4px] relative">
        {data.properties?.map((prop, idx) => (
          <div 
            key={`prop-${idx}`} 
            className={`flex ${prop.type === 'gradient' ? 'items-start pt-1 h-[48px]' : 'items-center h-[28px]'} justify-between px-1 shrink-0`}
          >
            <span className={`text-neutral-300 text-xs whitespace-nowrap mr-2 ${prop.type === 'gradient' ? 'mt-0.5' : ''}`}>
                {prop.name}
            </span>
            <ValueDisplay property={prop} />
          </div>
        ))}

        {/* Ports */}
        <div className="flex flex-row justify-between shrink-0 mt-1">
            <div className="flex flex-col gap-[4px] w-1/2">
                {data.inputs?.map((port) => (
                    <div key={port.id} className="flex items-center gap-2 h-[24px] -ml-3 pl-1 shrink-0">
                         <PortDot type={port.type} isConnected={port.connected} />
                         <span className="text-neutral-300 text-xs truncate">{port.name}</span>
                    </div>
                ))}
            </div>

             <div className="flex flex-col gap-[4px] w-1/2 items-end">
                {data.outputs?.map((port) => (
                    <div key={port.id} className="flex items-center gap-2 h-[24px] -mr-3 pr-1 justify-end shrink-0">
                         <span className="text-neutral-300 text-xs truncate text-right">{port.name}</span>
                         <PortDot type={port.type} isConnected={true} /> 
                    </div>
                ))}
            </div>
        </div>
      </div>
    </div>
  );
};

