        <span className="truncate">{data.name}</span>
      </div>

      {/* Body */}
      <div className="flex flex-col flex-1 p-[8px] gap-[4px] relative">
        {data.properties?.map((prop, idx) => {
          const isGradient = prop.type === 'gradient';
          return (
            <div 
              key={`prop-${idx}`} 
              className={`flex ${isGradient ? 'flex-col h-[60px]' : 'items-center justify-between h-[28px]'} px-1 shrink-0`}
            >
              <span className={`text-neutral-300 text-xs whitespace-nowrap ${isGradient ? 'mb-1' : 'mr-2'}`}>
                  {prop.name}
              </span>
              <ValueDisplay property={prop} />
            </div>
          );
        })}

        {/* Ports */}
        <div className="flex flex-row justify-between shrink-0 mt-1">
            <div className="flex flex-col gap-[4px] w-1/2">
                {data.inputs?.map((port) => (
                    <div key={port.id} className="flex items-center gap-2 h-[24px] -ml-3 pl-1 shrink-0">
                         <PortDot type={port.type} isConnected={port.connected} />
                         <span className="text-neutral-300 text-xs truncate">{port.name}</span>
                    </div>
                ))}
            </div>

             <div className="flex flex-col gap-[4px] w-1/2 items-end">
                {data.outputs?.map((port) => (
                    <div key={port.id} className="flex items-center gap-2 h-[24px] -mr-3 pr-1 justify-end shrink-0">
                         <span className="text-neutral-300 text-xs truncate text-right">{port.name}</span>
                         <PortDot type={port.type} isConnected={true} /> 
                    </div>
                ))}
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { GraphSchema, ViewportState, NodeData } from '../../types';
import { NodeWidget } from './NodeWidget';
import { ConnectionLine } from './ConnectionLine';
import { getPortPosition } from '../../utils';

interface GraphCanvasProps {
  schema: GraphSchema;
  onNodesChange?: (nodes: NodeData[]) => void;
}

type InteractionMode = 'IDLE' | 'PANNING' | 'DRAGGING_NODES' | 'BOX_SELECTING';

interface SelectionBox {
  startX: number; // Screen coords
  startY: number;
  currentX: number;
  currentY: number;
}

export const GraphCanvas: React.FC<GraphCanvasProps> = ({ schema, onNodesChange }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [viewport, setViewport] = useState<ViewportState>({ x: 0, y: 0, scale: 1 });
  const [selectedNodeIds, setSelectedNodeIds] = useState<Set<string>>(new Set());
  const [mode, setMode] = useState<InteractionMode>('IDLE');
  const [selectionBox, setSelectionBox] = useState<SelectionBox | null>(null);

  // Refs for interaction state
  const lastMousePosRef = useRef({ x: 0, y: 0 });
  // Map of NodeID -> { offsetX, offsetY } relative to mouse world pos at start of drag
  const dragOffsetsRef = useRef<Map<string, { x: number; y: number }>>(new Map());

  // Refs for data access in callbacks
  const viewportRef = useRef(viewport);
  const schemaRef = useRef(schema);

  useEffect(() => { viewportRef.current = viewport; }, [viewport]);
  useEffect(() => { schemaRef.current = schema; }, [schema]);

  // --- Helpers ---

  const screenToWorld = (sx: number, sy: number) => {
    const v = viewportRef.current;
    return {
      x: (sx - v.x) / v.scale,
      y: (sy - v.y) / v.scale
    };
  };

  // --- Handlers ---

  const handlePointerDown = (e: React.PointerEvent) => {
    // Only handle primary pointer (mouse left/right/middle or first touch)
    if (!e.isPrimary) return;

    const target = e.target as HTMLElement;
    const clickedNodeEl = target.closest('[data-node-id]');
    const clickedNodeId = clickedNodeEl?.getAttribute('data-node-id');

    // Right Click or Middle Click -> PANNING
    // (e.button 1 = Middle, 2 = Right)
    if (e.pointerType === 'mouse' && (e.button === 1 || e.button === 2)) {
      e.preventDefault();
      setMode('PANNING');
      lastMousePosRef.current = { x: e.clientX, y: e.clientY };
      containerRef.current?.setPointerCapture(e.pointerId);
      return;
    }

    // Left Click (button 0)
    if (e.button === 0) {
      if (clickedNodeId) {
        // --- DRAGGING NODES ---
        e.preventDefault(); // Prevent text selection
        setMode('DRAGGING_NODES');
        lastMousePosRef.current = { x: e.clientX, y: e.clientY };
        containerRef.current?.setPointerCapture(e.pointerId);

        // Logic for selection
        const newSelection = new Set(selectedNodeIds);
        if (e.shiftKey) {
          // Toggle
          if (newSelection.has(clickedNodeId)) newSelection.delete(clickedNodeId);
          else newSelection.add(clickedNodeId);
        } else {
          // If clicking an unselected node without shift, clear others and select this one.
          // If clicking a selected node, keep selection (to drag group).
          if (!newSelection.has(clickedNodeId)) {
            newSelection.clear();
            newSelection.add(clickedNodeId);
          }
        }
        setSelectedNodeIds(newSelection);

        // Calculate offsets for all selected nodes
        const worldMouse = screenToWorld(e.clientX, e.clientY);
        const offsets = new Map();
        schemaRef.current.nodes.forEach(node => {
          if (newSelection.has(node.id)) {
            offsets.set(node.id, {
              x: node.position.x - worldMouse.x,
              y: node.position.y - worldMouse.y
            });
          }
        });
        dragOffsetsRef.current = offsets;

      } else {
        // --- BOX SELECTING ---
        e.preventDefault();
        setMode('BOX_SELECTING');
        setSelectionBox({
          startX: e.clientX,
          startY: e.clientY,
          currentX: e.clientX,
          currentY: e.clientY
        });
        containerRef.current?.setPointerCapture(e.pointerId);

        // Clear selection unless shift
        if (!e.shiftKey) {
            setSelectedNodeIds(new Set());
        }
      }
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (mode === 'IDLE') return;
    if (e.pointerType === 'touch') e.preventDefault();

    if (mode === 'PANNING') {
      const dx = e.clientX - lastMousePosRef.current.x;
      const dy = e.clientY - lastMousePosRef.current.y;
      setViewport(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy }));
      lastMousePosRef.current = { x: e.clientX, y: e.clientY };
    } 
    else if (mode === 'DRAGGING_NODES') {
      const worldMouse = screenToWorld(e.clientX, e.clientY);

      const updatedNodes = schemaRef.current.nodes.map(node => {
        const offset = dragOffsetsRef.current.get(node.id);
        if (offset) {
          return {
            ...node,
            position: {
              x: worldMouse.x + offset.x,
              y: worldMouse.y + offset.y
            }
          };
        }
        return node;
      });

      if (onNodesChange) {
        onNodesChange(updatedNodes);
      }
    } 
    else if (mode === 'BOX_SELECTING') {
       setSelectionBox(prev => prev ? ({ ...prev, currentX: e.clientX, currentY: e.clientY }) : null);

       // Calculate Intersection logic for immediate feedback (Yellow Outline)
       if (selectionBox) {
           const sb = selectionBox;
           // Define box rect in screen space (always positive width/height)
           const boxLeft = Math.min(sb.startX, e.clientX);
           const boxTop = Math.min(sb.startY, e.clientY);
           const boxRight = Math.max(sb.startX, e.clientX);
           const boxBottom = Math.max(sb.startY, e.clientY);

           // Convert box to world space is hard because rotation/scale.
           // Easier: Convert Node Rects to Screen Space and check intersection
           const newSelection = new Set(selectedNodeIds); // Preserve if shift? Simplify: rebuild based on interaction

           // If shift was not held at start, we cleared selection. 
           // If we want to support shift-drag-box adding, we need to know initial state.
           // For simplicity, box select = whatever is in box.
           const currentSelection = new Set<string>();

           const v = viewportRef.current;
           schemaRef.current.nodes.forEach(node => {
               // Node Screen Rect
               const nx = (node.position.x * v.scale) + v.x;
               const ny = (node.position.y * v.scale) + v.y;
               const nw = node.size.width * v.scale;
               const nh = node.size.height * v.scale; // Approx, heights vary but schema has data.

               // Check overlap
               const isOverlapping = !(
                   nx > boxRight || 
                   nx + nw < boxLeft || 
                   ny > boxBottom || 
                   ny + nh < boxTop
               );

               if (isOverlapping) {
                   currentSelection.add(node.id);
               }
           });

           // Merging logic can be added here if Shift support is needed for box select
           setSelectedNodeIds(currentSelection);
       }
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (mode !== 'IDLE') {
        setMode('IDLE');
        setSelectionBox(null);
        if (containerRef.current?.hasPointerCapture(e.pointerId)) {
            containerRef.current.releasePointerCapture(e.pointerId);
        }
    }
  };

  const handleWheel = (e: React.WheelEvent) => {
    e.stopPropagation();
    const zoomSensitivity = 0.001;
    const delta = -e.deltaY * zoomSensitivity;
    const currentScale = viewportRef.current.scale;
    const newScale = Math.min(Math.max(0.1, currentScale + delta), 5);

    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return;

    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    const worldX = (mouseX - viewportRef.current.x) / currentScale;
    const worldY = (mouseY - viewportRef.current.y) / currentScale;

    const newX = mouseX - (worldX * newScale);
    const newY = mouseY - (worldY * newScale);

    setViewport({ x: newX, y: newY, scale: newScale });
  };

  // --- Rendering ---

  const connectionLines = schema.connections.map((conn, idx) => {
    const actualSourceNode = schema.nodes.find(n => n.outputs?.some(o => o.id === conn.from));
    const actualTargetNode = schema.nodes.find(n => n.inputs?.some(i => i.id === conn.to));

    if (!actualSourceNode || !actualTargetNode) return null;

    const start = getPortPosition(actualSourceNode, conn.from, 'output');
    const end = getPortPosition(actualTargetNode, conn.to, 'input');

    const sourcePortDef = actualSourceNode.outputs?.find(o => o.id === conn.from);
    const targetPortDef = actualTargetNode.inputs?.find(i => i.id === conn.to);

    if (start && end && sourcePortDef && targetPortDef) {
      return (
        <ConnectionLine
          key={`${conn.from}-${conn.to}-${idx}`}
          x1={start.x}
          y1={start.y}
          x2={end.x}
          y2={end.y}
          sourceType={sourcePortDef.type}
          targetType={targetPortDef.type}
        />
      );
    }
    return null;
  });

  return (
    <div 
      ref={containerRef}
      className={`w-full h-full bg-[#111] overflow-hidden relative touch-none select-none outline-none
        ${mode === 'PANNING' ? 'cursor-grabbing' : ''}
        ${mode === 'DRAGGING_NODES' ? 'cursor-move' : ''}
        ${mode === 'IDLE' ? 'cursor-default' : ''}
        ${mode === 'BOX_SELECTING' ? 'cursor-crosshair' : ''}
      `}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onLostPointerCapture={handlePointerUp}
      onWheel={handleWheel}
      onContextMenu={(e) => e.preventDefault()}
    >
        {/* Grid Background */}
        <div 
            className="absolute inset-0 pointer-events-none opacity-20"
            style={{
                backgroundImage: 'linear-gradient(#333 1px, transparent 1px), linear-gradient(90deg, #333 1px, transparent 1px)',
                backgroundSize: `${20 * viewport.scale}px ${20 * viewport.scale}px`,
                backgroundPosition: `${viewport.x}px ${viewport.y}px`
            }}
        />

        {/* World Transform Layer */}
        <div 
            style={{
                transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.scale})`,
                transformOrigin: '0 0',
                width: '100%',
                height: '100%',
                position: 'absolute',
                top: 0,
                left: 0
            }}
        >
            <svg className="absolute top-0 left-0 overflow-visible pointer-events-none w-1 h-1">
                {connectionLines}
            </svg>

            {schema.nodes.map(node => (
                <NodeWidget 
                    key={node.id} 
                    data={node} 
                    isSelected={selectedNodeIds.has(node.id)}
                />
            ))}
        </div>

        {/* Selection Box Overlay */}
        {mode === 'BOX_SELECTING' && selectionBox && (
            <div 
                className="absolute border-2 border-dashed border-blue-400 bg-blue-400/10 rounded-lg pointer-events-none z-50"
                style={{
                    left: Math.min(selectionBox.startX, selectionBox.currentX),
                    top: Math.min(selectionBox.startY, selectionBox.currentY),
                    width: Math.abs(selectionBox.currentX - selectionBox.startX),
                    height: Math.abs(selectionBox.currentY - selectionBox.startY),
                }}
            />
        )}

        {/* HUD */}
        <div className="absolute bottom-4 left-4 bg-black/50 p-2 rounded text-xs text-neutral-400 font-mono pointer-events-none select-none">
            Zoom: {Math.round(viewport.scale * 100)}% | X: {Math.round(viewport.x)} Y: {Math.round(viewport.y)} <br/>
            {selectedNodeIds.size > 0 ? `${selectedNodeIds.size} selected` : 'Right-click to pan'}
        </div>
    </div>
  );
};

import React, { useState } from 'react';
import { NodeData, NodeProperty } from '../../types';
import { getPortColor, isValidVector3, isValidColor, isValidGradient, generateGradientCSS, rgbToHex } from '../../utils';
import { AlertTriangle, HelpCircle } from 'lucide-react';
import { useToast } from '../UI/Toast';

interface NodeWidgetProps {
  data: NodeData;
  isSelected?: boolean;
}

const PortDot: React.FC<{ type: string; isConnected?: boolean }> = ({ type, isConnected }) => {
  const color = getPortColor(type);
  return (
    <div 
      className={`w-[12px] h-[12px] rounded-full border border-neutral-900 ${isConnected ? '' : 'opacity-80'}`}
      style={{ backgroundColor: color }}
    />
  );
};

// --- Gradient Specific Component ---
const GradientDisplay: React.FC<{ value: any }> = ({ value }) => {
  const { showToast } = useToast();
  const [selectedStopIndex, setSelectedStopIndex] = useState<number>(0);

  const handleCopy = (text: string, e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
    showToast('Copied to clipboard');
  };

  const valid = isValidGradient(value);
  const background = valid ? generateGradientCSS(value) : '#4b4b4b';

  if (!valid) {
    return (
      <div className="w-full h-[16px] rounded border border-neutral-600 shadow-sm relative overflow-hidden bg-neutral-800 flex items-center justify-center mt-1">
         <span className="text-[8px] text-neutral-400">Invalid Gradient</span>
      </div>
    );
  }

  const stops = value as Array<{ pos: number, color: number[] }>;
  const selectedStop = stops[selectedStopIndex] || stops[0];
  const selectedColorHex = rgbToHex(selectedStop.color);

  return (
    <div 
      className="w-full flex flex-col gap-1 pointer-events-auto mt-0.5"
      onPointerDown={(e) => e.stopPropagation()} // Prevent canvas pan/capture
    >
       {/* Gradient Bar with Markers */}
      <div className="h-[16px] rounded border border-neutral-600 shadow-sm relative" style={{ background }}>
         {stops.map((stop, idx) => {
            const isSelected = idx === selectedStopIndex;
            return (
                <div 
                    key={idx}
                    onClick={(e) => { e.stopPropagation(); setSelectedStopIndex(idx); }}
                    className={`absolute top-0 w-0 h-full border-l-2 cursor-pointer hover:border-white transition-colors z-10 ${isSelected ? 'border-white z-20' : 'border-black/40'}`}
                    style={{ left: `${Math.max(0, Math.min(1, stop.pos)) * 100}%` }}
                >
                    <div className={`absolute -top-[4px] -left-[3px] w-0 h-0 border-l-[3px] border-r-[3px] border-t-[4px] border-l-transparent border-r-transparent ${isSelected ? 'border-t-white' : 'border-t-black/60'}`} />
                </div>
            )
         })}
      </div>

      {/* Selected Stop Details */}
      <div className="flex items-center gap-1 h-[20px] bg-neutral-900/50 rounded px-1 border border-neutral-700/50">

         {/* Position Input Look-alike */}
         <div 
            className="flex items-center gap-1 px-1 hover:bg-neutral-700/50 rounded cursor-pointer group transition-colors"
            onClick={(e) => handleCopy(selectedStop.pos.toString(), e)}
            title="Click to copy position"
         >
             <span className="text-[9px] text-neutral-500 font-mono">Pos:</span>
             <span className="text-[10px] text-neutral-300 font-mono">{selectedStop.pos.toFixed(3)}</span>
         </div>

         <div className="w-[1px] h-[10px] bg-neutral-700 mx-1"/>

         {/* Color Input Look-alike */}
         <div 
            className="flex items-center gap-1 px-1 hover:bg-neutral-700/50 rounded cursor-pointer group flex-1 transition-colors"
            onClick={(e) => handleCopy(selectedColorHex, e)}
            title="Click to copy color hex"
         >
             <div className="w-[8px] h-[8px] rounded-sm border border-neutral-600" style={{ backgroundColor: selectedColorHex }} />
             <span className="text-[10px] text-neutral-300 font-mono">{selectedColorHex}</span>
         </div>
      </div>
    </div>
  );
};


const ValueDisplay: React.FC<{ property: NodeProperty }> = ({ property }) => {
  const { type, value } = property;
  const { showToast } = useToast();

  const handleCopy = (text: string, e: React.MouseEvent) => {
      e.stopPropagation();
      navigator.clipboard.writeText(text);
      showToast('Copied to clipboard');
  };

  // Common wrapper for pointer events
  const Wrapper = ({ children, copyValue, className = "" }: any) => (
    <div 
        onClick={(e) => handleCopy(copyValue || JSON.stringify(value), e)}
        onPointerDown={(e) => e.stopPropagation()} // Prevent canvas pan/capture
        className={`pointer-events-auto cursor-pointer hover:brightness-110 active:scale-95 transition-all relative group ${className}`}
        title="Click to copy"
    >
        {children}
    </div>
  );

  if (type === 'float') {
    const num = typeof value === 'number' ? value : parseFloat(value);
    if (isNaN(num)) return <span className="text-red-500 text-xs">NaN</span>;
    return (
      <Wrapper copyValue={num.toString()}>
        <div className="bg-neutral-700 px-2 py-0.5 rounded text-neutral-300 text-xs font-mono min-w-[40px] text-center border border-transparent hover:border-neutral-500">
            {num.toFixed(3)}
        </div>
      </Wrapper>
    );
  }

  if (type === 'vector3') {
    if (!isValidVector3(value)) {
       return <span className="text-red-500 text-[10px] flex items-center gap-1"><AlertTriangle size={10} /> Invalid Data</span>;
    }
    return (
      <Wrapper copyValue={JSON.stringify(value)}>
        <div className="flex gap-1 text-[10px] font-mono border border-transparent p-0.5 rounded hover:border-neutral-600 bg-neutral-900/30">
            <span className="bg-red-900/50 px-1 rounded text-red-200">{value[0].toFixed(1)}</span>
            <span className="bg-green-900/50 px-1 rounded text-green-200">{value[1].toFixed(1)}</span>
            <span className="bg-blue-900/50 px-1 rounded text-blue-200">{value[2].toFixed(1)}</span>
        </div>
      </Wrapper>
    );
  }

  if (type === 'color') {
    if (!isValidColor(value)) {
       return <div className="w-[32px] h-[16px] bg-black rounded border border-red-500 relative flex justify-center items-center"><HelpCircle size={10} className="text-red-500"/></div>;
    }
    const bg = `rgb(${value[0] * 255}, ${value[1] * 255}, ${value[2] * 255})`;
    const hex = rgbToHex(value);

    return (
      <Wrapper copyValue={hex}>
        <div className="flex items-center gap-2">
            <div className="w-[48px] h-[16px] rounded border border-neutral-600 shadow-sm" style={{ backgroundColor: bg }} />
        </div>
      </Wrapper>
    );
  }

  if (type === 'gradient') {
    return <GradientDisplay value={value} />;
  }

  if (type === 'string') {
    return (
      <Wrapper copyValue={String(value)}>
        <span className="text-neutral-400 text-xs italic truncate max-w-[100px] block hover:text-white" title={String(value)}>{String(value)}</span>
      </Wrapper>
    );
  }

  return <span className="text-neutral-500 text-xs">Unknown</span>;
};

export const NodeWidget: React.FC<NodeWidgetProps> = ({ data, isSelected }) => {
  const { x, y } = data.position;
  const { width, height } = data.size;

  let headerClass = "bg-neutral-700";
  if (data.type.includes("Input") || data.type.includes("Coord")) headerClass = "bg-red-900/80"; 
  if (data.type.includes("Output")) headerClass = "bg-neutral-800 border-b border-neutral-600";
  if (data.type.includes("Shader")) headerClass = "bg-green-900/60"; 
  if (data.type.includes("ValToRGB")) headerClass = "bg-yellow-900/60"; // Color Ramp specific

  const resizeHandleClass = "absolute w-3 h-3 bg-yellow-400 border border-black rounded-full z-50 pointer-events-auto hover:scale-125 transition-transform";

  return (
    <div
      data-node-id={data.id}
      className={`absolute flex flex-col rounded-lg shadow-2xl bg-neutral-800/95 overflow-visible text-sm select-none touch-none pointer-events-auto
        ${isSelected ? 'ring-2 ring-yellow-400 z-10' : 'border border-neutral-700'}`}
      style={{
        left: x,
        top: y,
        width: width,
        minHeight: height,
      }}
    >
      {/* Resize Handles (Only when selected) */}
      {isSelected && (
        <>
          <div data-resize-handle="nw" className={`${resizeHandleClass} -top-1.5 -left-1.5 cursor-nw-resize`} />
          <div data-resize-handle="ne" className={`${resizeHandleClass} -top-1.5 -right-1.5 cursor-ne-resize`} />
          <div data-resize-handle="sw" className={`${resizeHandleClass} -bottom-1.5 -left-1.5 cursor-sw-resize`} />
          <div data-resize-handle="se" className={`${resizeHandleClass} -bottom-1.5 -right-1.5 cursor-se-resize`} />
        </>
      )}

      {/* Header */}
      <div className={`h-[32px] px-3 ${headerClass} rounded-t-md text-white font-medium text-xs tracking-wide flex items-center justify-between shrink-0 overflow-hidden`}>
        <span className="truncate">{data.name}</span>
      </div>

      {/* Body */}
      <div className="flex flex-col flex-1 p-[8px] gap-[4px] relative overflow-hidden">
        {data.properties?.map((prop, idx) => {
          const isGradient = prop.type === 'gradient';
          return (
            <div 
              key={`prop-${idx}`} 
              className={`flex ${isGradient ? 'flex-col h-[60px]' : 'items-center justify-between h-[28px]'} px-1 shrink-0`}
            >
              <span className={`text-neutral-300 text-xs whitespace-nowrap ${isGradient ? 'mb-1' : 'mr-2'}`}>
                  {prop.name}
              </span>
              <ValueDisplay property={prop} />
            </div>
          );
        })}

        {/* Ports */}
        <div className="flex flex-row justify-between shrink-0 mt-1">
            <div className="flex flex-col gap-[4px] w-1/2">
                {data.inputs?.map((port) => (
                    <div key={port.id} className="flex items-center gap-2 h-[24px] -ml-3 pl-1 shrink-0">
                         <PortDot type={port.type} isConnected={port.connected} />
                         <span className="text-neutral-300 text-xs truncate">{port.name}</span>
                    </div>
                ))}
            </div>

             <div className="flex flex-col gap-[4px] w-1/2 items-end">
                {data.outputs?.map((port) => (
                    <div key={port.id} className="flex items-center gap-2 h-[24px] -mr-3 pr-1 justify-end shrink-0">
                         <span className="text-neutral-300 text-xs truncate text-right">{port.name}</span>
                         <PortDot type={port.type} isConnected={true} /> 
                    </div>
                ))}
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { GraphSchema, ViewportState, NodeData } from '../../types';
import { NodeWidget } from './NodeWidget';
import { ConnectionLine } from './ConnectionLine';
import { getPortPosition } from '../../utils';

interface GraphCanvasProps {
  schema: GraphSchema;
  onNodesChange?: (nodes: NodeData[]) => void;
}

type InteractionMode = 'IDLE' | 'PANNING' | 'DRAGGING_NODES' | 'BOX_SELECTING' | 'RESIZING_NODE';

interface SelectionBox {
  startX: number; // Screen coords
  startY: number;
  currentX: number;
  currentY: number;
}

interface ResizingState {
  nodeId: string;
  handle: string; // 'nw', 'ne', 'sw', 'se'
  startBound: { x: number; y: number; width: number; height: number };
}

export const GraphCanvas: React.FC<GraphCanvasProps> = ({ schema, onNodesChange }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [viewport, setViewport] = useState<ViewportState>({ x: 0, y: 0, scale: 1 });
  const [selectedNodeIds, setSelectedNodeIds] = useState<Set<string>>(new Set());
  const [mode, setMode] = useState<InteractionMode>('IDLE');
  const [selectionBox, setSelectionBox] = useState<SelectionBox | null>(null);

  // Refs for interaction state
  const lastMousePosRef = useRef({ x: 0, y: 0 }); // Screen coords
  const resizingStateRef = useRef<ResizingState | null>(null);
  const dragOffsetsRef = useRef<Map<string, { x: number; y: number }>>(new Map());

  // Refs for data access in callbacks
  const viewportRef = useRef(viewport);
  const schemaRef = useRef(schema);

  useEffect(() => { viewportRef.current = viewport; }, [viewport]);
  useEffect(() => { schemaRef.current = schema; }, [schema]);

  // --- Helpers ---

  const screenToWorld = (sx: number, sy: number) => {
    const v = viewportRef.current;
    return {
      x: (sx - v.x) / v.scale,
      y: (sy - v.y) / v.scale
    };
  };

  // --- Handlers ---

  const handlePointerDown = (e: React.PointerEvent) => {
    if (!e.isPrimary) return;

    const target = e.target as HTMLElement;

    // Check for Resize Handle FIRST
    const resizeHandle = target.getAttribute('data-resize-handle');
    const clickedNodeEl = target.closest('[data-node-id]');
    const clickedNodeId = clickedNodeEl?.getAttribute('data-node-id');

    // Right/Middle Click -> Pan
    if (e.pointerType === 'mouse' && (e.button === 1 || e.button === 2)) {
      e.preventDefault();
      setMode('PANNING');
      lastMousePosRef.current = { x: e.clientX, y: e.clientY };
      containerRef.current?.setPointerCapture(e.pointerId);
      return;
    }

    if (e.button === 0) {
      // --- RESIZING ---
      if (resizeHandle && clickedNodeId) {
        e.preventDefault();
        e.stopPropagation(); // Stop bubbling so we don't trigger node drag
        setMode('RESIZING_NODE');

        const node = schemaRef.current.nodes.find(n => n.id === clickedNodeId);
        if (node) {
          resizingStateRef.current = {
            nodeId: clickedNodeId,
            handle: resizeHandle,
            startBound: { x: node.position.x, y: node.position.y, width: node.size.width, height: node.size.height }
          };
        }
        lastMousePosRef.current = { x: e.clientX, y: e.clientY };
        containerRef.current?.setPointerCapture(e.pointerId);
        return;
      }

      // --- NODE DRAG / SELECT ---
      if (clickedNodeId) {
        e.preventDefault();
        setMode('DRAGGING_NODES');
        lastMousePosRef.current = { x: e.clientX, y: e.clientY };
        containerRef.current?.setPointerCapture(e.pointerId);

        const newSelection = new Set(selectedNodeIds);
        if (e.shiftKey) {
          if (newSelection.has(clickedNodeId)) newSelection.delete(clickedNodeId);
          else newSelection.add(clickedNodeId);
        } else {
          if (!newSelection.has(clickedNodeId)) {
            newSelection.clear();
            newSelection.add(clickedNodeId);
          }
        }
        setSelectedNodeIds(newSelection);

        const worldMouse = screenToWorld(e.clientX, e.clientY);
        const offsets = new Map();
        schemaRef.current.nodes.forEach(node => {
          if (newSelection.has(node.id)) {
            offsets.set(node.id, {
              x: node.position.x - worldMouse.x,
              y: node.position.y - worldMouse.y
            });
          }
        });
        dragOffsetsRef.current = offsets;

      } else {
        // --- BOX SELECT ---
        e.preventDefault();
        setMode('BOX_SELECTING');
        setSelectionBox({
          startX: e.clientX,
          startY: e.clientY,
          currentX: e.clientX,
          currentY: e.clientY
        });
        containerRef.current?.setPointerCapture(e.pointerId);

        if (!e.shiftKey) {
            setSelectedNodeIds(new Set());
        }
      }
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (mode === 'IDLE') return;
    if (e.pointerType === 'touch') e.preventDefault();

    if (mode === 'PANNING') {
      const dx = e.clientX - lastMousePosRef.current.x;
      const dy = e.clientY - lastMousePosRef.current.y;
      setViewport(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy }));
      lastMousePosRef.current = { x: e.clientX, y: e.clientY };
    } 
    else if (mode === 'DRAGGING_NODES') {
      const worldMouse = screenToWorld(e.clientX, e.clientY);

      const updatedNodes = schemaRef.current.nodes.map(node => {
        const offset = dragOffsetsRef.current.get(node.id);
        if (offset) {
          return {
            ...node,
            position: {
              x: worldMouse.x + offset.x,
              y: worldMouse.y + offset.y
            }
          };
        }
        return node;
      });

      if (onNodesChange) {
        onNodesChange(updatedNodes);
      }
    }
    else if (mode === 'RESIZING_NODE' && resizingStateRef.current) {
        const { nodeId, handle, startBound } = resizingStateRef.current;
        const scale = viewportRef.current.scale;

        // Calculate total delta from start of drag
        const dx = (e.clientX - lastMousePosRef.current.x) / scale;
        const dy = (e.clientY - lastMousePosRef.current.y) / scale;

        // We need to calculate based on accumulated delta if we were storing startBound from initial click.
        // Wait, lastMousePosRef is updated in other modes, but for resize, let's just use raw difference from *previous* frame
        // OR better: use startBound and total screen delta.
        // Let's use simple incremental delta logic which is robust against scale.

        // Actually, easiest way is to re-calc based on current mouse vs initial mouse, but we only stored last frame in other modes.
        // Let's adapt. We will update `lastMousePosRef` at end of this block.

        const updatedNodes = schemaRef.current.nodes.map(node => {
            if (node.id !== nodeId) return node;

            let { x, y, width, height } = node.position ? { ...node.position, ...node.size } : { x: 0, y: 0, width: 100, height: 100 };

            // Min size
            const MIN_W = 100;
            const MIN_H = 50;

            if (handle.includes('e')) {
                width = Math.max(MIN_W, width + dx);
            }
            if (handle.includes('s')) {
                height = Math.max(MIN_H, height + dy);
            }
            if (handle.includes('w')) {
                const newWidth = Math.max(MIN_W, width - dx);
                // Only move X if we haven't hit min width
                if (newWidth !== width) {
                    x += dx;
                    width = newWidth;
                }
            }
            if (handle.includes('n')) {
                const newHeight = Math.max(MIN_H, height - dy);
                if (newHeight !== height) {
                    y += dy;
                    height = newHeight;
                }
            }

            return {
                ...node,
                position: { x, y },
                size: { width, height }
            };
        });

        if (onNodesChange) onNodesChange(updatedNodes);
        lastMousePosRef.current = { x: e.clientX, y: e.clientY };
    }
    else if (mode === 'BOX_SELECTING') {
       setSelectionBox(prev => prev ? ({ ...prev, currentX: e.clientX, currentY: e.clientY }) : null);

       if (selectionBox) {
           const sb = selectionBox;
           const boxLeft = Math.min(sb.startX, e.clientX);
           const boxTop = Math.min(sb.startY, e.clientY);
           const boxRight = Math.max(sb.startX, e.clientX);
           const boxBottom = Math.max(sb.startY, e.clientY);

           const currentSelection = new Set<string>();
           const v = viewportRef.current;
           schemaRef.current.nodes.forEach(node => {
               const nx = (node.position.x * v.scale) + v.x;
               const ny = (node.position.y * v.scale) + v.y;
               const nw = node.size.width * v.scale;
               const nh = node.size.height * v.scale;

               const isOverlapping = !(
                   nx > boxRight || 
                   nx + nw < boxLeft || 
                   ny > boxBottom || 
                   ny + nh < boxTop
               );

               if (isOverlapping) {
                   currentSelection.add(node.id);
               }
           });

           setSelectedNodeIds(currentSelection);
       }
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (mode !== 'IDLE') {
        setMode('IDLE');
        setSelectionBox(null);
        resizingStateRef.current = null;
        if (containerRef.current?.hasPointerCapture(e.pointerId)) {
            containerRef.current.releasePointerCapture(e.pointerId);
        }
    }
  };

  const handleWheel = (e: React.WheelEvent) => {
    e.stopPropagation();
    const zoomSensitivity = 0.001;
    const delta = -e.deltaY * zoomSensitivity;
    const currentScale = viewportRef.current.scale;
    const newScale = Math.min(Math.max(0.1, currentScale + delta), 5);

    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return;

    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    const worldX = (mouseX - viewportRef.current.x) / currentScale;
    const worldY = (mouseY - viewportRef.current.y) / currentScale;

    const newX = mouseX - (worldX * newScale);
    const newY = mouseY - (worldY * newScale);

    setViewport({ x: newX, y: newY, scale: newScale });
  };

  // --- Rendering ---

  const connectionLines = schema.connections.map((conn, idx) => {
    const actualSourceNode = schema.nodes.find(n => n.outputs?.some(o => o.id === conn.from));
    const actualTargetNode = schema.nodes.find(n => n.inputs?.some(i => i.id === conn.to));

    if (!actualSourceNode || !actualTargetNode) return null;

    const start = getPortPosition(actualSourceNode, conn.from, 'output');
    const end = getPortPosition(actualTargetNode, conn.to, 'input');

    const sourcePortDef = actualSourceNode.outputs?.find(o => o.id === conn.from);
    const targetPortDef = actualTargetNode.inputs?.find(i => i.id === conn.to);

    if (start && end && sourcePortDef && targetPortDef) {
      return (
        <ConnectionLine
          key={`${conn.from}-${conn.to}-${idx}`}
          x1={start.x}
          y1={start.y}
          x2={end.x}
          y2={end.y}
          sourceType={sourcePortDef.type}
          targetType={targetPortDef.type}
        />
      );
    }
    return null;
  });

  return (
    <div 
      ref={containerRef}
      className={`w-full h-full bg-[#111] overflow-hidden relative touch-none select-none outline-none
        ${mode === 'PANNING' ? 'cursor-grabbing' : ''}
        ${mode === 'DRAGGING_NODES' ? 'cursor-move' : ''}
        ${mode === 'IDLE' ? 'cursor-default' : ''}
        ${mode === 'BOX_SELECTING' ? 'cursor-crosshair' : ''}
        ${mode === 'RESIZING_NODE' ? 'cursor-nwse-resize' : ''} 
      `}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onLostPointerCapture={handlePointerUp}
      onWheel={handleWheel}
      onContextMenu={(e) => e.preventDefault()}
    >
        {/* Grid Background */}
        <div 
            className="absolute inset-0 pointer-events-none opacity-20"
            style={{
                backgroundImage: 'linear-gradient(#333 1px, transparent 1px), linear-gradient(90deg, #333 1px, transparent 1px)',
                backgroundSize: `${20 * viewport.scale}px ${20 * viewport.scale}px`,
                backgroundPosition: `${viewport.x}px ${viewport.y}px`
            }}
        />

        {/* World Transform Layer */}
        <div 
            style={{
                transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.scale})`,
                transformOrigin: '0 0',
                width: '100%',
                height: '100%',
                position: 'absolute',
                top: 0,
                left: 0
            }}
        >
            <svg className="absolute top-0 left-0 overflow-visible pointer-events-none w-1 h-1">
                {connectionLines}
            </svg>

            {schema.nodes.map(node => (
                <NodeWidget 
                    key={node.id} 
                    data={node} 
                    isSelected={selectedNodeIds.has(node.id)}
                />
            ))}
        </div>

        {/* Selection Box Overlay */}
        {mode === 'BOX_SELECTING' && selectionBox && (
            <div 
                className="absolute border-2 border-dashed border-blue-400 bg-blue-400/10 rounded-lg pointer-events-none z-50"
                style={{
                    left: Math.min(selectionBox.startX, selectionBox.currentX),
                    top: Math.min(selectionBox.startY, selectionBox.currentY),
                    width: Math.abs(selectionBox.currentX - selectionBox.startX),
                    height: Math.abs(selectionBox.currentY - selectionBox.startY),
                }}
            />
        )}

        {/* HUD */}
        <div className="absolute bottom-4 left-4 bg-black/50 p-2 rounded text-xs text-neutral-400 font-mono pointer-events-none select-none">
            Zoom: {Math.round(viewport.scale * 100)}% | X: {Math.round(viewport.x)} Y: {Math.round(viewport.y)} <br/>
            {selectedNodeIds.size > 0 ? `${selectedNodeIds.size} selected` : 'Right-click to pan'}
        </div>
    </div>
  );
};

