import React, { useState } from 'react';
import { NodeData, NodePort } from '../../types';
import { getPortColor, isValidVector3, isValidColor, isValidGradient, generateGradientCSS, rgbToHex } from '../../utils';
import { AlertTriangle, HelpCircle } from 'lucide-react';
import { useToast } from '../UI/Toast';

interface NodeWidgetProps {
  data: NodeData;
  isSelected?: boolean;
}

const PortDot: React.FC<{ type: string; isConnected?: boolean }> = ({ type, isConnected }) => {
  const color = getPortColor(type);
  return (
    <div 
      className={`w-[12px] h-[12px] rounded-full border border-neutral-900 ${isConnected ? '' : 'opacity-80'} shrink-0`}
      style={{ backgroundColor: color }}
    />
  );
};

// --- Widgets ---

const FloatCurveDisplay: React.FC<{ value: any }> = ({ value }) => {
    const { showToast } = useToast();
    const [selectedPointIndex, setSelectedPointIndex] = useState<number>(0);

    if (!Array.isArray(value)) return <div className="h-24 bg-neutral-900 border border-red-900 flex items-center justify-center text-[10px] text-red-500">Invalid Curve</div>;

    // Normalize and sort
    const points = value
        .filter(p => typeof p.x === 'number' && typeof p.y === 'number')
        .sort((a, b) => a.x - b.x);

    const selectedPoint = points[selectedPointIndex] || points[0];

    const handleCopy = (text: string, e: React.MouseEvent) => {
        e.stopPropagation();
        navigator.clipboard.writeText(text);
        showToast('Copied to clipboard');
    };

    // Generate Path
    let pathD = "";
    if (points.length > 0) {
        pathD = `M ${points[0].x * 100} ${100 - (points[0].y * 100)}`;
        for (let i = 1; i < points.length; i++) {
             pathD += ` L ${points[i].x * 100} ${100 - (points[i].y * 100)}`;
        }
    } else {
        pathD = "M 0 100 L 100 0";
    }

    return (
        <div className="w-full flex flex-col gap-1 pointer-events-auto mt-1" onPointerDown={e => e.stopPropagation()}>
            <div className="w-full h-28 bg-[#222] border border-neutral-600 rounded relative select-none overflow-hidden">
                {/* Grid Lines */}
                <div className="absolute inset-0 opacity-20 pointer-events-none" 
                     style={{ backgroundImage: 'linear-gradient(#444 1px, transparent 1px), linear-gradient(90deg, #444 1px, transparent 1px)', backgroundSize: '25% 25%' }} 
                />

                {/* Curve Line */}
                <svg className="absolute inset-0 w-full h-full pointer-events-none" viewBox="0 0 100 100" preserveAspectRatio="none">
                    <path d={pathD} fill="none" stroke="#a1a1a1" strokeWidth="2" vectorEffect="non-scaling-stroke"/>
                </svg>

                {/* Point Markers (HTML div to avoid aspect ratio distortion) */}
                {points.map((p, i) => (
                    <div 
                        key={i}
                        className={`absolute w-[7px] h-[7px] rounded-full border border-neutral-900 cursor-pointer transition-all z-10 hover:scale-125
                            ${i === selectedPointIndex ? 'bg-white ring-1 ring-neutral-400 scale-125 z-20' : 'bg-[#6363C7]'}`}
                        style={{
                            left: `${p.x * 100}%`,
                            bottom: `${p.y * 100}%`,
                            transform: 'translate(-50%, 50%)' 
                        }}
                        onClick={(e) => {
                            e.stopPropagation();
                            setSelectedPointIndex(i);
                        }}
                    />
                ))}
            </div>

            {/* Details Panel */}
             <div className="flex items-center gap-1 h-[20px] bg-neutral-900/50 rounded px-1 border border-neutral-700/50">
                {selectedPoint ? (
                    <>
                        <div 
                            className="flex items-center gap-1 px-1 hover:bg-neutral-700/50 rounded cursor-pointer group transition-colors min-w-0 flex-1"
                            onClick={(e) => handleCopy(selectedPoint.x.toString(), e)}
                            title="Copy X position"
                        >
                            <span className="text-[9px] text-neutral-500 font-mono">X:</span>
                            <span className="text-[10px] text-neutral-300 font-mono truncate">{selectedPoint.x.toFixed(3)}</span>
                        </div>
                        <div className="w-[1px] h-[10px] bg-neutral-700 mx-1"/>
                        <div 
                            className="flex items-center gap-1 px-1 hover:bg-neutral-700/50 rounded cursor-pointer group transition-colors min-w-0 flex-1"
                             onClick={(e) => handleCopy(selectedPoint.y.toString(), e)}
                             title="Copy Y value"
                        >
                             <span className="text-[9px] text-neutral-500 font-mono">Y:</span>
                             <span className="text-[10px] text-neutral-300 font-mono truncate">{selectedPoint.y.toFixed(3)}</span>
                        </div>
                    </>
                ) : <span className="text-[9px] text-neutral-500 p-1">No point selected</span>}
             </div>
        </div>
    )
}

const GradientDisplay: React.FC<{ value: any }> = ({ value }) => {
  const { showToast } = useToast();
  const [selectedStopIndex, setSelectedStopIndex] = useState<number>(0);

  const handleCopy = (text: string, e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
    showToast('Copied to clipboard');
  };

  const valid = isValidGradient(value);
  const background = valid ? generateGradientCSS(value) : '#4b4b4b';

  if (!valid) return null;

  const stops = value as Array<{ pos: number, color: number[] }>;
  const selectedStop = stops[selectedStopIndex] || stops[0];
  const selectedColorHex = rgbToHex(selectedStop.color);

  return (
    <div 
      className="w-full flex flex-col gap-1 pointer-events-auto mt-1"
      onPointerDown={(e) => e.stopPropagation()} 
    >
      <div className="h-[16px] rounded border border-neutral-600 shadow-sm relative" style={{ background }}>
         {stops.map((stop, idx) => {
            const isSelected = idx === selectedStopIndex;
            return (
                <div 
                    key={idx}
                    onClick={(e) => { e.stopPropagation(); setSelectedStopIndex(idx); }}
                    className={`absolute top-0 w-0 h-full border-l-2 cursor-pointer hover:border-white transition-colors z-10 ${isSelected ? 'border-white z-20' : 'border-black/40'}`}
                    style={{ left: `${Math.max(0, Math.min(1, stop.pos)) * 100}%` }}
                >
                    <div className={`absolute -top-[4px] -left-[3px] w-0 h-0 border-l-[3px] border-r-[3px] border-t-[4px] border-l-transparent border-r-transparent ${isSelected ? 'border-t-white' : 'border-t-black/60'}`} />
                </div>
            )
         })}
      </div>

      <div className="flex items-center gap-1 h-[20px] bg-neutral-900/50 rounded px-1 border border-neutral-700/50">
         <div 
            className="flex items-center gap-1 px-1 hover:bg-neutral-700/50 rounded cursor-pointer group transition-colors"
            onClick={(e) => handleCopy(selectedStop.pos.toString(), e)}
            title="Click to copy position"
         >
             <span className="text-[9px] text-neutral-500 font-mono">Pos:</span>
             <span className="text-[10px] text-neutral-300 font-mono">{selectedStop.pos.toFixed(3)}</span>
         </div>

         <div className="w-[1px] h-[10px] bg-neutral-700 mx-1"/>

         <div 
            className="flex items-center gap-1 px-1 hover:bg-neutral-700/50 rounded cursor-pointer group flex-1 transition-colors"
            onClick={(e) => handleCopy(selectedColorHex, e)}
            title="Click to copy color hex"
         >
             <div className="w-[8px] h-[8px] rounded-sm border border-neutral-600" style={{ backgroundColor: selectedColorHex }} />
             <span className="text-[10px] text-neutral-300 font-mono">{selectedColorHex}</span>
         </div>
      </div>
    </div>
  );
};

const ValueWidget: React.FC<{ type: string; value: any }> = ({ type, value }) => {
    const { showToast } = useToast();
    const copy = (val: string) => {
        navigator.clipboard.writeText(val);
        showToast("Copied");
    }

    if (type === 'float') {
        const num = typeof value === 'number' ? value : parseFloat(value);
        if (isNaN(num)) return <span className="text-red-500 text-[10px]">NaN</span>;
        return (
            <div 
                className="bg-neutral-700 px-2 py-0.5 rounded text-neutral-300 text-xs font-mono min-w-[40px] text-center border border-transparent hover:border-neutral-500 cursor-pointer ml-auto"
                onPointerDown={e => e.stopPropagation()}
                onClick={() => copy(num.toString())}
            >
                {num.toFixed(3)}
            </div>
        );
    }
    if (type === 'vector3') {
        if (!isValidVector3(value)) return null;
        return (
            <div className="flex gap-1 ml-auto">
                {['X', 'Y', 'Z'].map((axis, i) => (
                     <div 
                        key={axis} 
                        className="flex items-center justify-center bg-neutral-900/50 rounded px-1.5 h-[18px] min-w-[32px] cursor-pointer hover:bg-neutral-800 transition-colors"
                        onPointerDown={e => e.stopPropagation()}
                        onClick={(e) => {
                            e.stopPropagation();
                            copy(value[i].toString());
                        }}
                        title={`Copy ${axis}`}
                     >
                         <span className={`text-[10px] font-mono leading-none ${
                             i===0 ? 'text-red-400' : 
                             i===1 ? 'text-[#4ade80]' : // Green-400
                             'text-blue-400'
                         }`}>
                             {value[i]?.toFixed(2)}
                         </span>
                     </div>
                ))}
            </div>
        )
    }
    if (type === 'color') {
        if (!isValidColor(value)) return null;
        const bg = `rgb(${value[0] * 255}, ${value[1] * 255}, ${value[2] * 255})`;
        return (
             <div 
                className="w-[40px] h-[18px] rounded border border-neutral-600 shadow-sm ml-auto cursor-pointer" 
                style={{ backgroundColor: bg }} 
                onClick={() => copy(JSON.stringify(value))}
                onPointerDown={e => e.stopPropagation()}
             />
        );
    }
    if (type === 'string') {
        return <div className="ml-auto text-xs bg-black/20 px-1 rounded truncate max-w-[80px]">{String(value)}</div>
    }
    if (type === 'gradient') return <GradientDisplay value={value} />;
    if (type === 'float_curve') return <FloatCurveDisplay value={value} />;
    if (type === 'geometry') return null; // Geometry has no value widget

    return null;
}

const InputRow: React.FC<{ port: NodePort }> = ({ port }) => {
    // Logic:
    // Connected: Show Dot + Label. (Widget hidden).
    // Not Connected:
    //    Hide Port: Show Label + Widget. No Dot.
    //    Show Port: Show Dot + Label + Widget.

    const showDot = port.connected || (!port.connected && !port.hide_port);
    const showWidget = !port.connected; 

    // Large widgets (Gradient, Curve) break onto a new line
    const isLargeWidget = port.type === 'gradient' || port.type === 'float_curve';

    return (
        <div className={`flex flex-col min-h-[24px] justify-center ${isLargeWidget ? 'mb-2' : ''}`}>
             <div className="flex items-center gap-2 h-[24px]">
                 {/* Port Dot */}
                 <div className={`w-[12px] flex items-center justify-center ${!showDot ? 'invisible' : ''}`}>
                     <PortDot type={port.type} isConnected={port.connected} />
                 </div>

                 {/* Label */}
                 <span className="text-neutral-300 text-xs truncate select-none">{port.name}</span>

                 {/* Inline Widget (if not connected and small) */}
                 {showWidget && !isLargeWidget && (
                     <ValueWidget type={port.type} value={port.value} />
                 )}
             </div>

             {/* Block Widget (if not connected and large) */}
             {showWidget && isLargeWidget && (
                 <div className="pl-4 pr-1">
                      <ValueWidget type={port.type} value={port.value} />
                 </div>
             )}
        </div>
    )
}

const OutputRow: React.FC<{ port: NodePort }> = ({ port }) => {
    return (
        <div className="flex items-center justify-end gap-2 h-[24px] w-full">
            <span className="text-neutral-300 text-xs truncate text-right select-none">{port.name}</span>
            <PortDot type={port.type} isConnected={true} /> 
        </div>
    )
}

export const NodeWidget: React.FC<NodeWidgetProps> = ({ data, isSelected }) => {
  const { x, y } = data.position;
  // Handle optional size gracefully
  const width = data.size?.width ?? 200;
  const height = data.size?.height ?? 100;

  let headerClass = "bg-neutral-700";
  if (data.type.includes("Input") || data.type.includes("Coord")) headerClass = "bg-red-900/80"; 
  if (data.type.includes("Output")) headerClass = "bg-neutral-800 border-b border-neutral-600";
  if (data.type.includes("Shader")) headerClass = "bg-green-900/60"; 
  if (data.type.includes("Geometry")) headerClass = "bg-emerald-900/60";
  if (data.type.includes("ValToRGB")) headerClass = "bg-yellow-900/60"; 

  const baseHandleClass = "absolute z-50 pointer-events-auto bg-transparent";
  const cornerSize = "w-3 h-3";

  return (
    <div
      data-node-id={data.id}
      className={`absolute flex flex-col rounded-lg shadow-2xl bg-neutral-800/95 overflow-visible text-sm select-none touch-none pointer-events-auto
        ${isSelected ? 'ring-2 ring-yellow-400 z-10' : 'border border-neutral-700'}`}
      style={{
        left: x,
        top: y,
        width: width,
        minHeight: height,
      }}
    >
      {/* Handles */}
      <div data-resize-handle="nw" className={`${baseHandleClass} ${cornerSize} -top-1.5 -left-1.5 cursor-nw-resize`} />
      <div data-resize-handle="ne" className={`${baseHandleClass} ${cornerSize} -top-1.5 -right-1.5 cursor-ne-resize`} />
      <div data-resize-handle="sw" className={`${baseHandleClass} ${cornerSize} -bottom-1.5 -left-1.5 cursor-sw-resize`} />
      <div data-resize-handle="se" className={`${baseHandleClass} ${cornerSize} -bottom-1.5 -right-1.5 cursor-se-resize`} />
      <div data-resize-handle="n" className={`${baseHandleClass} cursor-n-resize h-[6px] -top-[3px] left-2 right-2`} />
      <div data-resize-handle="s" className={`${baseHandleClass} cursor-s-resize h-[6px] -bottom-[3px] left-2 right-2`} />
      <div data-resize-handle="w" className={`${baseHandleClass} cursor-w-resize w-[6px] -left-[3px] top-2 bottom-2`} />
      <div data-resize-handle="e" className={`${baseHandleClass} cursor-e-resize w-[6px] -right-[3px] top-2 bottom-2`} />

      {/* Header */}
      <div className={`h-[32px] px-3 ${headerClass} rounded-t-md text-white font-medium text-xs tracking-wide flex items-center justify-between shrink-0 overflow-hidden`}>
        <span className="truncate">{data.name}</span>
      </div>

      {/* Body: Outputs First, Then Inputs */}
      <div className="flex flex-col flex-1 p-[8px] gap-[4px] relative overflow-hidden">

        {/* Outputs Section */}
        {data.outputs && data.outputs.length > 0 && (
             <div className="flex flex-col gap-[4px] w-full items-end border-b border-neutral-700/30 pb-1 mb-1">
                {data.outputs.map((port) => (
                    <OutputRow key={port.id} port={port} />
                ))}
            </div>
        )}

        {/* Inputs Section */}
        {data.inputs && data.inputs.length > 0 && (
             <div className="flex flex-col gap-[4px] w-full -ml-1">
                {data.inputs.map((port) => (
                    <InputRow key={port.id} port={port} />
                ))}
            </div>
        )}

      </div>
    </div>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { GraphSchema, ViewportState, NodeData } from '../../types';
import { NodeWidget } from './NodeWidget';
import { ConnectionLine } from './ConnectionLine';
import { getPortPosition, calculateNodeContentSize } from '../../utils';

interface GraphCanvasProps {
  schema: GraphSchema;
  onNodesChange?: (nodes: NodeData[]) => void;
  onInteractionEnd?: () => void;
}

type InteractionMode = 'IDLE' | 'PANNING' | 'DRAGGING_NODES' | 'BOX_SELECTING' | 'RESIZING_NODE' | 'PINCH_ZOOM';

interface SelectionBox {
  startX: number; // Screen coords
  startY: number;
  currentX: number;
  currentY: number;
}

interface ResizingState {
  nodeId: string;
  handle: string; // 'nw', 'ne', 'sw', 'se', 'n', 's', 'e', 'w'
  startBound: { x: number; y: number; width: number; height: number };
  startMouse: { x: number; y: number }; // Screen coords
}

interface PinchState {
    startDist: number;
    startScale: number;
    startCenter: { x: number; y: number }; // Screen coords
    startViewportPos: { x: number; y: number };
}

export const GraphCanvas: React.FC<GraphCanvasProps> = ({ schema, onNodesChange, onInteractionEnd }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [viewport, setViewport] = useState<ViewportState>({ x: 0, y: 0, scale: 1 });
  const [selectedNodeIds, setSelectedNodeIds] = useState<Set<string>>(new Set());
  const [mode, setMode] = useState<InteractionMode>('IDLE');
  const [selectionBox, setSelectionBox] = useState<SelectionBox | null>(null);

  // Refs for interaction state
  const activePointersRef = useRef<Map<number, { x: number; y: number }>>(new Map());
  const lastMousePosRef = useRef({ x: 0, y: 0 }); // Screen coords (used for pan/drag)
  const resizingStateRef = useRef<ResizingState | null>(null);
  const dragOffsetsRef = useRef<Map<string, { x: number; y: number }>>(new Map());
  const pinchRef = useRef<PinchState | null>(null);

  // Refs for data access in callbacks
  const viewportRef = useRef(viewport);
  const schemaRef = useRef(schema);

  useEffect(() => { viewportRef.current = viewport; }, [viewport]);
  useEffect(() => { schemaRef.current = schema; }, [schema]);

  // --- Helpers ---

  const screenToWorld = (sx: number, sy: number) => {
    const v = viewportRef.current;
    return {
      x: (sx - v.x) / v.scale,
      y: (sy - v.y) / v.scale
    };
  };

  const getPointerDistance = (p1: {x:number, y:number}, p2: {x:number, y:number}) => {
      return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
  };

  const getPointerCenter = (p1: {x:number, y:number}, p2: {x:number, y:number}) => {
      return { x: (p1.x + p2.x) / 2, y: (p1.y + p2.y) / 2 };
  };

  // --- Handlers ---

  const handlePointerDown = (e: React.PointerEvent) => {
    // Capture pointer to track movements outside div if needed (standard for drag)
    containerRef.current?.setPointerCapture(e.pointerId);
    activePointersRef.current.set(e.pointerId, { x: e.clientX, y: e.clientY });

    const target = e.target as HTMLElement;
    const resizeHandle = target.getAttribute('data-resize-handle');
    const clickedNodeEl = target.closest('[data-node-id]');
    const clickedNodeId = clickedNodeEl?.getAttribute('data-node-id');

    // --- CHECK MULTI-TOUCH (PINCH) ---
    if (activePointersRef.current.size === 2) {
        const points: { x: number; y: number }[] = Array.from(activePointersRef.current.values());
        if (points[0] && points[1]) {
            const dist = getPointerDistance(points[0], points[1]);
            const center = getPointerCenter(points[0], points[1]);

            setMode('PINCH_ZOOM');
            pinchRef.current = {
                startDist: dist,
                startScale: viewportRef.current.scale,
                startViewportPos: { x: viewportRef.current.x, y: viewportRef.current.y },
                startCenter: center
            };
            // Clear other modes artifacts
            setSelectionBox(null);
            return;
        }
    }

    // --- SINGLE POINTER INTERACTION ---
    if (activePointersRef.current.size === 1) {
        // Right/Middle Click -> Mouse Pan
        if (e.pointerType === 'mouse' && (e.button === 1 || e.button === 2)) {
            e.preventDefault();
            setMode('PANNING');
            lastMousePosRef.current = { x: e.clientX, y: e.clientY };
            return;
        }

        if (e.button === 0) { // Primary Button (or Touch)

            // 1. Resizing (Priority)
            if (resizeHandle && clickedNodeId) {
                e.preventDefault();
                e.stopPropagation();
                setMode('RESIZING_NODE');

                const node = schemaRef.current.nodes.find(n => n.id === clickedNodeId);
                if (node) {
                    resizingStateRef.current = {
                        nodeId: clickedNodeId,
                        handle: resizeHandle,
                        startBound: { 
                            x: node.position.x, 
                            y: node.position.y, 
                            width: node.size?.width ?? 200, 
                            height: node.size?.height ?? 100 
                        },
                        startMouse: { x: e.clientX, y: e.clientY }
                    };
                }
                return;
            }

            // 2. Node Interaction
            if (clickedNodeId) {
                e.preventDefault();
                setMode('DRAGGING_NODES');
                lastMousePosRef.current = { x: e.clientX, y: e.clientY };

                // Logic: Touch -> Simple Select & Drag. Mouse -> Standard Shift/Click Select.
                if (e.pointerType === 'touch') {
                    // Mobile: Drop selection logic, just drag the touched node.
                    // If we want to support multi-touch drag later, this might need changing, 
                    // but "drop the selection" request implies simplicity.
                    const newSelection = new Set([clickedNodeId]);
                    setSelectedNodeIds(newSelection);

                    // Calc offsets
                    const worldMouse = screenToWorld(e.clientX, e.clientY);
                    const offsets = new Map();
                    const node = schemaRef.current.nodes.find(n => n.id === clickedNodeId);
                    if (node) {
                        offsets.set(node.id, { x: node.position.x - worldMouse.x, y: node.position.y - worldMouse.y });
                    }
                    dragOffsetsRef.current = offsets;

                } else {
                    // Desktop: Standard Logic
                    const newSelection = new Set(selectedNodeIds);
                    if (e.shiftKey) {
                        if (newSelection.has(clickedNodeId)) newSelection.delete(clickedNodeId);
                        else newSelection.add(clickedNodeId);
                    } else {
                        if (!newSelection.has(clickedNodeId)) {
                            newSelection.clear();
                            newSelection.add(clickedNodeId);
                        }
                    }
                    setSelectedNodeIds(newSelection);

                    const worldMouse = screenToWorld(e.clientX, e.clientY);
                    const offsets = new Map();
                    schemaRef.current.nodes.forEach(node => {
                        if (newSelection.has(node.id)) {
                            offsets.set(node.id, {
                                x: node.position.x - worldMouse.x,
                                y: node.position.y - worldMouse.y
                            });
                        }
                    });
                    dragOffsetsRef.current = offsets;
                }
                return;
            }

            // 3. Background Interaction
            e.preventDefault();

            if (e.pointerType === 'touch') {
                // Mobile: Pan on background
                setMode('PANNING');
            } else {
                // Desktop: Box Select
                setMode('BOX_SELECTING');
                setSelectionBox({
                    startX: e.clientX,
                    startY: e.clientY,
                    currentX: e.clientX,
                    currentY: e.clientY
                });
                if (!e.shiftKey) setSelectedNodeIds(new Set());
            }
            lastMousePosRef.current = { x: e.clientX, y: e.clientY };
        }
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    // Update pointer tracker
    if (activePointersRef.current.has(e.pointerId)) {
        activePointersRef.current.set(e.pointerId, { x: e.clientX, y: e.clientY });
    }

    if (mode === 'IDLE') return;
    if (e.pointerType === 'touch') e.preventDefault();

    // --- PINCH ZOOM ---
    if (mode === 'PINCH_ZOOM' && activePointersRef.current.size === 2 && pinchRef.current) {
        const points: { x: number; y: number }[] = Array.from(activePointersRef.current.values());

        if (points[0] && points[1]) {
            const currDist = getPointerDistance(points[0], points[1]);
            const currCenter = getPointerCenter(points[0], points[1]);

            const { startDist, startScale, startViewportPos, startCenter } = pinchRef.current;

            // Calculate Scale
            // Limit zoom
            let newScale = startScale * (currDist / startDist);
            newScale = Math.min(Math.max(0.1, newScale), 5);

            // Calculate Position
            // We want the world point that was under startCenter to now be under currCenter
            // WorldPoint = (StartCenter - StartViewport) / StartScale
            // NewViewport = CurrCenter - (WorldPoint * NewScale)

            const worldPointX = (startCenter.x - startViewportPos.x) / startScale;
            const worldPointY = (startCenter.y - startViewportPos.y) / startScale;

            const newX = currCenter.x - (worldPointX * newScale);
            const newY = currCenter.y - (worldPointY * newScale);

            setViewport({ x: newX, y: newY, scale: newScale });
        }
        return;
    }

    // --- PANNING ---
    if (mode === 'PANNING') {
      // Find the active pointer (should be just one if we are here, or use event)
      // Since handlePointerMove fires for the moving pointer, e.clientX is correct.
      // But if we switched from Pinch to Pan, we need to be careful.
      // We rely on lastMousePosRef which we update at the end of this block.

      const dx = e.clientX - lastMousePosRef.current.x;
      const dy = e.clientY - lastMousePosRef.current.y;
      setViewport(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy }));
      lastMousePosRef.current = { x: e.clientX, y: e.clientY };
    } 

    // --- DRAGGING NODES ---
    else if (mode === 'DRAGGING_NODES') {
      const worldMouse = screenToWorld(e.clientX, e.clientY);

      const updatedNodes = schemaRef.current.nodes.map(node => {
        const offset = dragOffsetsRef.current.get(node.id);
        if (offset) {
          return {
            ...node,
            position: {
              x: worldMouse.x + offset.x,
              y: worldMouse.y + offset.y
            }
          };
        }
        return node;
      });

      if (onNodesChange) {
        onNodesChange(updatedNodes);
      }
    }

    // --- RESIZING ---
    else if (mode === 'RESIZING_NODE' && resizingStateRef.current) {
        const { nodeId, handle, startBound, startMouse } = resizingStateRef.current;
        const scale = viewportRef.current.scale;

        const dx = (e.clientX - startMouse.x) / scale;
        const dy = (e.clientY - startMouse.y) / scale;

        const updatedNodes = schemaRef.current.nodes.map(node => {
            if (node.id !== nodeId) return node;

            const { width: minW, height: minH } = calculateNodeContentSize(node);

            let { x, y, width, height } = startBound;

            if (handle.includes('e')) width = Math.max(minW, startBound.width + dx);
            if (handle.includes('w')) {
                const desiredWidth = startBound.width - dx;
                width = Math.max(minW, desiredWidth);
                const fixedRight = startBound.x + startBound.width;
                x = fixedRight - width;
            }
            if (handle.includes('s')) height = Math.max(minH, startBound.height + dy);
            if (handle.includes('n')) {
                const desiredHeight = startBound.height - dy;
                height = Math.max(minH, desiredHeight);
                const fixedBottom = startBound.y + startBound.height;
                y = fixedBottom - height;
            }

            return { ...node, position: { x, y }, size: { width, height } };
        });

        if (onNodesChange) onNodesChange(updatedNodes);
    }

    // --- BOX SELECT ---
    else if (mode === 'BOX_SELECTING') {
       setSelectionBox(prev => prev ? ({ ...prev, currentX: e.clientX, currentY: e.clientY }) : null);

       if (selectionBox) {
           const sb = selectionBox;
           const boxLeft = Math.min(sb.startX, e.clientX);
           const boxTop = Math.min(sb.startY, e.clientY);
           const boxRight = Math.max(sb.startX, e.clientX);
           const boxBottom = Math.max(sb.startY, e.clientY);

           const currentSelection = new Set<string>();
           const v = viewportRef.current;
           schemaRef.current.nodes.forEach(node => {
               const nodeW = node.size?.width ?? 200;
               const nodeH = node.size?.height ?? 100;
               const nx = (node.position.x * v.scale) + v.x;
               const ny = (node.position.y * v.scale) + v.y;
               const nw = nodeW * v.scale;
               const nh = nodeH * v.scale;

               if (!(nx > boxRight || nx + nw < boxLeft || ny > boxBottom || ny + nh < boxTop)) {
                   currentSelection.add(node.id);
               }
           });
           setSelectedNodeIds(currentSelection);
       }
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    activePointersRef.current.delete(e.pointerId);
    if (containerRef.current?.hasPointerCapture(e.pointerId)) {
        containerRef.current.releasePointerCapture(e.pointerId);
    }

    if (mode === 'PINCH_ZOOM') {
        if (activePointersRef.current.size < 2) {
             if (activePointersRef.current.size === 1) {
                 const remaining = activePointersRef.current.values().next().value;
                 if (remaining) {
                     lastMousePosRef.current = { ...remaining };
                     setMode('PANNING');
                 } else {
                     setMode('IDLE');
                 }
             } else {
                 setMode('IDLE');
             }
        }
    } else if (activePointersRef.current.size === 0) {
        if (mode !== 'IDLE') {
            // Trigger save if we were modifying nodes
            if ((mode === 'DRAGGING_NODES' || mode === 'RESIZING_NODE') && onInteractionEnd) {
                onInteractionEnd();
            }

            setMode('IDLE');
            setSelectionBox(null);
            resizingStateRef.current = null;
        }
    }
  };

  const handleWheel = (e: React.WheelEvent) => {
    e.stopPropagation();
    const zoomSensitivity = 0.001;
    const delta = -e.deltaY * zoomSensitivity;
    const currentScale = viewportRef.current.scale;
    const newScale = Math.min(Math.max(0.1, currentScale + delta), 5);

    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return;

    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    const worldX = (mouseX - viewportRef.current.x) / currentScale;
    const worldY = (mouseY - viewportRef.current.y) / currentScale;

    const newX = mouseX - (worldX * newScale);
    const newY = mouseY - (worldY * newScale);

    setViewport({ x: newX, y: newY, scale: newScale });
  };

  // --- Rendering ---

  const connectionLines = schema.connections.map((conn, idx) => {
    const actualSourceNode = schema.nodes.find(n => n.outputs?.some(o => o.id === conn.from));
    const actualTargetNode = schema.nodes.find(n => n.inputs?.some(i => i.id === conn.to));

    if (!actualSourceNode || !actualTargetNode) return null;

    const start = getPortPosition(actualSourceNode, conn.from, 'output');
    const end = getPortPosition(actualTargetNode, conn.to, 'input');

    const sourcePortDef = actualSourceNode.outputs?.find(o => o.id === conn.from);
    const targetPortDef = actualTargetNode.inputs?.find(i => i.id === conn.to);

    if (start && end && sourcePortDef && targetPortDef) {
      return (
        <ConnectionLine
          key={`${conn.from}-${conn.to}-${idx}`}
          x1={start.x}
          y1={start.y}
          x2={end.x}
          y2={end.y}
          sourceType={sourcePortDef.type}
          targetType={targetPortDef.type}
        />
      );
    }
    return null;
  });

  return (
    <div 
      ref={containerRef}
      className={`w-full h-full bg-[#111] overflow-hidden relative touch-none select-none outline-none
        ${mode === 'PANNING' ? 'cursor-grabbing' : ''}
        ${mode === 'DRAGGING_NODES' ? 'cursor-move' : ''}
        ${mode === 'IDLE' ? 'cursor-default' : ''}
        ${mode === 'BOX_SELECTING' ? 'cursor-crosshair' : ''}
        ${mode === 'RESIZING_NODE' ? 'cursor-nwse-resize' : ''} 
      `}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onLostPointerCapture={handlePointerUp}
      onWheel={handleWheel}
      onContextMenu={(e) => e.preventDefault()}
    >
        {/* Grid Background */}
        <div 
            className="absolute inset-0 pointer-events-none opacity-20"
            style={{
                backgroundImage: 'linear-gradient(#333 1px, transparent 1px), linear-gradient(90deg, #333 1px, transparent 1px)',
                backgroundSize: `${20 * viewport.scale}px ${20 * viewport.scale}px`,
                backgroundPosition: `${viewport.x}px ${viewport.y}px`
            }}
        />

        {/* World Transform Layer */}
        <div 
            style={{
                transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.scale})`,
                transformOrigin: '0 0',
                width: '100%',
                height: '100%',
                position: 'absolute',
                top: 0,
                left: 0
            }}
        >
            <svg className="absolute top-0 left-0 overflow-visible pointer-events-none w-1 h-1">
                {connectionLines}
            </svg>

            {schema.nodes.map(node => (
                <NodeWidget 
                    key={node.id} 
                    data={node} 
                    isSelected={selectedNodeIds.has(node.id)}
                />
            ))}
        </div>

        {/* Selection Box Overlay */}
        {mode === 'BOX_SELECTING' && selectionBox && (
            <div 
                className="absolute border-2 border-dashed border-blue-400 bg-blue-400/10 rounded-lg pointer-events-none z-50"
                style={{
                    left: Math.min(selectionBox.startX, selectionBox.currentX),
                    top: Math.min(selectionBox.startY, selectionBox.currentY),
                    width: Math.abs(selectionBox.currentX - selectionBox.startX),
                    height: Math.abs(selectionBox.currentY - selectionBox.startY),
                }}
            />
        )}

        {/* HUD */}
        <div className="absolute bottom-4 left-4 bg-black/50 p-2 rounded text-xs text-neutral-400 font-mono pointer-events-none select-none z-50">
            Zoom: {Math.round(viewport.scale * 100)}% | X: {Math.round(viewport.x)} Y: {Math.round(viewport.y)} <br/>
            {selectedNodeIds.size > 0 ? `${selectedNodeIds.size} selected` : 'Right-click to pan'}
        </div>
    </div>
  );
};

export type DataType = 'float' | 'vector3' | 'color' | 'string' | 'gradient' | 'float_curve' | 'geometry' | 'rotation' | string;

export interface Position {
  x: number;
  y: number;
}

export interface Size {
  width: number;
  height: number;
}

export interface NodePort {
  id: string;
  name: string;
  type: DataType;
  value?: any;
  connected?: boolean;
  hide_port?: boolean;
}

export interface NodeData {
  id: string;
  name: string;
  type: string;
  position: Position;
  size?: Size;
  inputs?: NodePort[];
  outputs?: NodePort[];
}

export interface ConnectionData {
  from: string;
  to: string;
}

export interface GraphSchema {
  nodes: NodeData[];
  connections: ConnectionData[];
}

export interface ViewportState {
  x: number;
  y: number;
  scale: number;
}

import { DataType } from './types';

// Blender Shader Editor Colors
export const TYPE_COLORS: Record<string, string> = {
  float: '#A1A1A1', // Grey
  vector3: '#6363C7', // Purple
  color: '#C7C729', // Yellow
  string: '#63C7C7', // Cyan/Blueish
  shader: '#63C763', // Green (Common in Blender)
  geometry: '#00D6A3', // Blender Geometry (Turquoise-Green)
  rotation: '#a563c6', // Euler Angles (Purple-Pink)
